function asRecord(value: unknown): JsonRecord {
  return typeof value === "object" && value !== null ? (value as JsonRecord) : {};
}

function asArray<T = unknown>(value: unknown): T[] {
  return Array.isArray(value) ? (value as T[]) : [];
}

function asString(value: unknown): string {
  if (typeof value === "string") return value.trim();
  if (typeof value === "number" || typeof value === "bigint") return String(value);
  return "";
}

function asNumber(value: unknown): number {
  if (typeof value === "number" && Number.isFinite(value)) return value;
  if (typeof value === "string" && value.trim()) {
    const parsed = Number(value);
    return Number.isFinite(parsed) ? parsed : 0;
  }
  return 0;
}

function modelLabel(value: unknown, fallback: string): string {
  const label = asString(asRecord(value).model_used);
  return label || fallback;
}

function clamp(value: number, min: number, max: number): number {
  return Math.min(max, Math.max(min, value));
}

function sentence(value: string): string {
  return value.trim().replace(/\s+/g, " ");
}

function escapeRegExp(value: string): string {
  return value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function textIncludesToken(text: string, token: string): boolean {
  const normalizedText = sentence(text).toLowerCase();
  const normalizedToken = sentence(token).toLowerCase();
  if (!normalizedText || !normalizedToken) return false;
  if (normalizedToken.length <= 6) {
    return new RegExp(`\\b${escapeRegExp(normalizedToken)}\\b`, "i").test(normalizedText);
  }
  return normalizedText.includes(normalizedToken);
}

function compactNarrative(value: string, options?: { maxSentences?: number; maxChars?: number }): string {
  const maxSentences = options?.maxSentences ?? 2;
  const maxChars = options?.maxChars ?? 340;
  const normalized = sentence(value);
  if (!normalized) return "";

  // Protect decimal-like fragments inside long chemical names so sentence splitting
  // does not break on patterns like "7. 3. 0.".
  const protectedText = normalized.replace(/(\d)\.\s(?=\d)/g, "$1__DOT__ ");
  const rawSentences =
    protectedText
      .match(/[^.!?]+[.!?]?/g)
      ?.map((part) => sentence(part).replace(/__DOT__/g, "."))
      .filter(Boolean) ?? [normalized];
  const seen = new Set<string>();
  const kept: string[] = [];

  for (const part of rawSentences) {
    const key = part.toLowerCase().replace(/[^a-z0-9]+/g, " ").trim();
    if (!key || seen.has(key)) continue;
    seen.add(key);
    kept.push(part);
    if (kept.length >= maxSentences) break;
  }

  const joined = sentence(kept.join(" "));
  if (joined.length <= maxChars) return joined;
  return `${joined.slice(0, maxChars).trimEnd()}…`;
}

function sanitizeReportText(value: string): string {
  let text = sentence(value);
  if (!text) return "";
  const replacements: Record<string, string> = {
    "medium-strength": "mid-tier",
    "high-strength": "higher-tier",
    "low-strength": "lower-tier"
  };
  for (const [source, target] of Object.entries(replacements)) {
    text = text.replaceAll(source, target).replaceAll(capitalize(source), capitalize(target));
  }
  return text;
}

function capitalize(value: string): string {
  return value ? value[0].toUpperCase() + value.slice(1) : value;
}

function inferStudyType(title: string, abstract: string): string {
  const combined = `${title} ${abstract}`.toLowerCase();
  if (combined.includes("randomized") || combined.includes("placebo")) return "randomized trial";
  if (combined.includes("phase 3")) return "phase 3 trial";
  if (combined.includes("phase 2")) return "phase 2 trial";
  if (combined.includes("phase 1")) return "phase 1 trial";
  if (combined.includes("meta-analysis")) return "meta-analysis";
  if (combined.includes("review")) return "review";
  if (combined.includes("cohort")) return "cohort";
  if (combined.includes("case-control")) return "case-control";
  if (combined.includes("mouse") || combined.includes("murine")) return "animal study";
  if (combined.includes("cell") || combined.includes("in vitro")) return "preclinical";
  return "literature";
}

function inferPopulation(title: string, abstract: string): string {
  const combined = `${title} ${abstract}`.toLowerCase();
  if (combined.includes("patient") || combined.includes("human") || combined.includes("participants")) {
    return "human";
  }
  if (combined.includes("mouse") || combined.includes("murine") || combined.includes("rat")) {
    return "animal";
  }
  if (combined.includes("cell") || combined.includes("organoid") || combined.includes("in vitro")) {
    return "preclinical";
  }
  return "mixed";
}

function inferClinicalMaturity(title: string, abstract: string): "high" | "medium" | "low" {
  const combined = `${title} ${abstract}`.toLowerCase();
  if (
    combined.includes("phase 3") ||
    combined.includes("randomized") ||
    combined.includes("double-blind") ||
    combined.includes("patients")
  ) {
    return "high";
  }
  if (combined.includes("phase 2") || combined.includes("cohort") || combined.includes("human")) {
    return "medium";
  }
  return "low";
}

function inferEvidenceStrength(
  attention: number,
  title: string,
  abstract: string,
  year: number
): "high" | "medium" | "low" {
  const combined = `${title} ${abstract}`.toLowerCase();
  if (
    attention >= 75 ||
    combined.includes("meta-analysis") ||
    combined.includes("systematic review") ||
    combined.includes("phase 3")
  ) {
    return "high";
  }
  if (attention >= 10 || year >= 2020 || combined.includes("phase 2") || combined.includes("randomized")) {
    return "medium";
  }
  return "low";
}

function inferRiskLevel(title: string, abstract: string, paper: JsonRecord): "high" | "medium" | "low" {
  if (Boolean(paper.retraction_flag) || Boolean(paper.concern_flag)) return "high";
  if (Boolean(paper.correction_flag) || Boolean(paper.preprint_flag)) return "medium";
  const combined = `${title} ${abstract}`.toLowerCase();
  if (
    combined.includes("toxicity") ||
    combined.includes("adverse event") ||
    combined.includes("microhemorrhage") ||
    combined.includes("black box")
  ) {
    return "medium";
  }
  return "low";
}

function buildPaperFlags(paper: JsonRecord, riskLevel: "high" | "medium" | "low"): string {
  const flags: string[] = [];
  if (Boolean(paper.retraction_flag)) flags.push("Retraction");
  if (Boolean(paper.concern_flag)) flags.push("Expression of concern");
  if (Boolean(paper.correction_flag)) flags.push("Correction");
  if (Boolean(paper.guideline_citation_flag)) flags.push("Guideline citation");
  if (Boolean(paper.preprint_flag)) flags.push("Preprint");
  if (flags.length > 0) return flags.join(" / ");
  return riskLevel === "medium" ? "Moderate interpretive risk" : "No flagged integrity concerns";
}

function paperEvidenceSnippets(paper: JsonRecord): string[] {
  return asArray<string>(paper.evidence_snippets).map(asString).filter(Boolean);
}

function paperEvidenceText(paper: JsonRecord): string {
  const snippets = paperEvidenceSnippets(paper);
  if (snippets.length > 0) {
    return sentence(`${asString(paper.title)} ${snippets.join(" ")}`);
  }
  return sentence(`${asString(paper.title)} ${asString(paper.abstract)}`);
}

function paperHasTargetedSourceVerification(paper: JsonRecord): boolean {
  return asString(paper.content_level) === "full_text" && paperEvidenceSnippets(paper).length > 0;
}

function buildLiteraturePaperCards(literature: JsonRecord): LiteraturePaperCard[] {
  return asArray<JsonRecord>(literature.papers).slice(0, 8).map((paper) => {
    const title = asString(paper.title);
    const abstract = asString(paper.abstract);
    const year = asNumber(paper.year);
    const attention = asNumber(paper.citation_count);
    const studyType = inferStudyType(title, abstract);
    const clinicalMaturity = inferClinicalMaturity(title, abstract);
    const evidenceStrength = inferEvidenceStrength(attention, title, abstract, year);
    const riskLevel = inferRiskLevel(title, abstract, paper);
    return {
      pmid: asString(paper.pmid),
      title,
      content_level: asString(paper.content_level) === "full_text" ? "full_text" : "abstract",
      evidence_strength: evidenceStrength,
      clinical_maturity: clinicalMaturity,
      risk_level: riskLevel,
      study_type: studyType,
      population: inferPopulation(title, abstract),
      year,
      attention,
      flags: buildPaperFlags(paper, riskLevel),
      abstract
    };
  });
}

function buildLiteratureMap(cards: LiteraturePaperCard[]): Record<string, LiteraturePaperCard> {
  return Object.fromEntries(cards.filter((card) => card.pmid).map((card) => [card.pmid, card]));
}

function buildLiteratureRetrievalNote(literature: JsonRecord): string {
  const stats = asRecord(literature.retrieval_stats);
  const retrieved = asNumber(stats.retrieved_count);
  const preliminary = asNumber(stats.preliminary_selection_count);
  const finalShortlist = asNumber(stats.final_shortlist_count);
  const excludedByCentrality = asNumber(stats.excluded_by_centrality_count);
  const excludedAsGeneric = asNumber(stats.excluded_as_generic_non_disease_count);
  const excludedAsUmbrella = asNumber(stats.excluded_as_umbrella_title_count);

  if (retrieved <= 0) {
    return "No papers were retrieved in the current literature pass.";
  }
  if (finalShortlist <= 0) {
    const reasons: string[] = [];
    if (excludedByCentrality > 0) reasons.push(`${excludedByCentrality} lacked enough disease focus`);
    if (excludedAsGeneric > 0) reasons.push(`${excludedAsGeneric} stayed too general`);
    if (excludedAsUmbrella > 0) reasons.push(`${excludedAsUmbrella} remained umbrella-style reviews`);
    return reasons.length > 0
      ? `${retrieved} papers were retrieved, but none cleared the current disease-specific filter; ${reasons.join(", ")}.`
      : `${retrieved} papers were retrieved, but none cleared the current disease-specific reportability filter.`;
  }
  if (preliminary > 0 && preliminary !== finalShortlist) {
    const softReason =
      excludedByCentrality > 0
        ? "some papers remained too indirect for the final shortlist"
        : excludedAsGeneric > 0 || excludedAsUmbrella > 0
          ? "some papers stayed too broad for the final shortlist"
          : "";
    return softReason
      ? `${retrieved} papers were retrieved, ${preliminary} entered reranking, and ${finalShortlist} cleared the disease-specific filter; ${softReason}.`
      : `${retrieved} papers were retrieved, ${preliminary} entered reranking, and ${finalShortlist} cleared the disease-specific reportability filter.`;
  }
  return `${retrieved} papers were retrieved, and ${finalShortlist} cleared the disease-specific reportability filter.`;
}

function buildLiteratureDiagnostics(literature: JsonRecord): LiteratureDiagnostics | undefined {
  const stats = asRecord(literature.retrieval_stats);
  const retrieved = asNumber(stats.retrieved_count);
  const preliminary = asNumber(stats.preliminary_selection_count);
  const finalShortlist = asNumber(stats.final_shortlist_count);
  const excludedByCentrality = asNumber(stats.excluded_by_centrality_count);
  const excludedAsGeneric = asNumber(stats.excluded_as_generic_non_disease_count);
  const excludedAsUmbrella = asNumber(stats.excluded_as_umbrella_title_count);

  if (
    retrieved <= 0 &&
    preliminary <= 0 &&
    finalShortlist <= 0 &&
    excludedByCentrality <= 0 &&
    excludedAsGeneric <= 0 &&
    excludedAsUmbrella <= 0
  ) {
    return undefined;
  }

  let bottleneckStage: LiteratureDiagnostics["bottleneck_stage"] = "unknown";
  let userSummary = "";

  if (retrieved <= 0) {
    bottleneckStage = "retrieval";
    userSummary = "The literature search did not recover reportable papers in this run, so the bottleneck was at the retrieval step.";
  } else if (finalShortlist <= 0) {
    bottleneckStage = preliminary > 0 ? "reranking" : "filtering";
    const reasons: string[] = [];
    if (excludedByCentrality > 0) reasons.push("papers stayed too indirect");
    if (excludedAsGeneric > 0) reasons.push("papers stayed too general");
    if (excludedAsUmbrella > 0) reasons.push("umbrella-style reviews were removed");
    userSummary =
      reasons.length > 0
        ? `The literature search found papers, but the main narrowing happened during disease-specific filtering: ${reasons.join(", ")}.`
        : "The literature search found papers, but the main narrowing happened during disease-specific filtering before a final shortlist was formed.";
  } else if (preliminary > 0 && finalShortlist < preliminary) {
    bottleneckStage = "reranking";
    userSummary = `The literature search was healthy overall; it narrowed from ${preliminary} reranked paper${preliminary === 1 ? "" : "s"} to ${finalShortlist} final paper${finalShortlist === 1 ? "" : "s"} for report assembly.`;
  } else {
    bottleneckStage = "healthy";
    userSummary = `The literature pass was healthy in this run, with ${finalShortlist} paper${finalShortlist === 1 ? "" : "s"} carrying forward into the final report set.`;
  }

  return {
    retrieved_count: retrieved,
    reranked_count: preliminary,
    final_shortlist_count: finalShortlist,
    bottleneck_stage: bottleneckStage,
    user_summary: userSummary
  };
}

function buildDrugdbRetrievalNote(drugdb: JsonRecord): string {
  const stats = asRecord(drugdb.retrieval_stats);
  const chemblTargets = asNumber(stats.chembl_target_count);
  const openTargetsRows = asNumber(stats.opentargets_drug_count);
  const activityMolecules = asNumber(stats.activity_molecule_count);
  const expandedCandidates = asNumber(stats.expanded_candidate_count);

  if (chemblTargets <= 0 && openTargetsRows <= 0 && activityMolecules <= 0) {
    return "No reportable drug-target evidence was recovered in the current drug database pass.";
  }
  return `${chemblTargets} ChEMBL targets, ${openTargetsRows} Open Targets drug rows, and ${activityMolecules} activity-linked molecules were reviewed; ${expandedCandidates} candidates entered downstream triage.`;
}

function buildRepurposingNote(repurposing: JsonRecord, drugdb: JsonRecord): string {
  const hypotheses = asArray<JsonRecord>(repurposing.hypotheses).length;
  const debug = asRecord(repurposing.debug);
  const filteredCount = asArray<JsonRecord>(debug.filtered_candidates).length;
  const expandedCount = asArray<JsonRecord>(drugdb.expanded_candidates).length;
  const salvageApplied = debug.salvage_applied === true;
  const topFilter = asRecord(asArray<JsonRecord>(debug.filter_summary)[0]);
  const topFilterCount = asNumber(topFilter.count);
  const topFilterMessage = asString(topFilter.user_message);

  if (hypotheses > 0) {
    return filteredCount > 0
      ? `${hypotheses} candidate idea${hypotheses === 1 ? "" : "s"} moved forward after a selective review of ${expandedCount || hypotheses} mechanism-linked leads.`
      : `${hypotheses} candidate idea${hypotheses === 1 ? "" : "s"} moved forward into scoring.`;
  }
  if (salvageApplied) {
    return "One mechanism-linked candidate was retained for review, but the shortlist remained cautious in this run.";
  }
  if (filteredCount > 0) {
    return topFilterCount > 0 && topFilterMessage
      ? `${filteredCount} mechanism-linked candidate${filteredCount === 1 ? "" : "s"} were reviewed, but none were strong enough to move forward; in most cases, ${topFilterMessage.charAt(0).toLowerCase()}${topFilterMessage.slice(1)}`
      : `${filteredCount} mechanism-linked candidate${filteredCount === 1 ? "" : "s"} were reviewed, but none were strong enough to move forward.`;
  }
  return "No candidate ideas were strong enough to move forward in this run.";
}

function buildEvidenceNote(evidence: JsonRecord, repurposing: JsonRecord): string {
  const scoreCount = asArray<JsonRecord>(evidence.scores).length;
  const hypothesisCount = asArray<JsonRecord>(repurposing.hypotheses).length;

  if (scoreCount > 0) {
    return `${scoreCount} candidate${scoreCount === 1 ? "" : "s"} progressed into structured scoring.`;
  }
  if (hypothesisCount > 0) {
    return "A shortlist was reviewed, but no candidate progressed into structured scoring in this run.";
  }
  return "Scoring did not continue because no shortlist moved forward from the candidate review stage.";
}

function buildRedTeamNote(redTeam: JsonRecord, evidence: JsonRecord): string {
  const critiqueCount = asArray<JsonRecord>(redTeam.critiques).length;
  const scoreCount = asArray<JsonRecord>(evidence.scores).length;

  if (critiqueCount > 0) {
    return `${critiqueCount} challenge note${critiqueCount === 1 ? "" : "s"} were added to stress-test the leading candidates.`;
  }
  if (scoreCount > 0) {
    return "The scored shortlist remained stable enough that no additional challenge notes were added in this run.";
  }
  return "Red-team review did not continue because no scored shortlist was available.";
}

function buildDrugContexts(drugdb: JsonRecord, query: string): DrugContext[] {
  const expanded = asArray<JsonRecord>(drugdb.expanded_candidates);
  if (expanded.length > 0) {
    return expanded.slice(0, 10).flatMap((row) => {
      const drugName = asString(row.drug_name);
      if (!drugName) return [];
      const currentIndications = asArray<string>(row.current_indications).filter(Boolean).slice(0, 6);
      const maxPhase = asNumber(row.max_phase);
      return [{
        drug_name: drugName,
        molecule_chembl_id: asString(row.molecule_chembl_id),
        current_indications: currentIndications,
        mechanism: asString(row.mechanism) || `Expanded candidate context for ${query}.`,
        target_symbol: asString(row.target_symbol),
        max_phase: maxPhase,
        is_approved: row.is_approved === true || maxPhase >= 4,
        source: asString(row.source).includes("chembl") ? "chembl_activity" as const : "opentargets" as const
      }];
    });
  }

  const openTargets = asArray<JsonRecord>(drugdb.opentargets_drugs);
  const rows: DrugContext[] = openTargets.slice(0, 8).flatMap((row) => {
    const drug = asRecord(row.drug);
    const drugName = asString(drug.name) || asString(drug.id);
    if (!drugName) return [];
    const phase = Math.max(asNumber(row.maxClinicalStage), asNumber(drug.maxClinicalStage), asNumber(drug.maximumClinicalStage));
    const diseaseNames = asArray<JsonRecord>(row.diseases)
      .map((item) => asString(asRecord(item.disease).name))
      .filter(Boolean)
      .slice(0, 4);
    return [{
      drug_name: drugName,
      molecule_chembl_id: asString(drug.id),
      current_indications: diseaseNames,
      mechanism: `Prioritized from OpenTargets disease-target-drug associations for ${query}.`,
      target_symbol: asString(row.target_symbol),
      max_phase: phase,
      is_approved: phase >= 4,
      source: "opentargets" as const
    }];
  });

  if (rows.length > 0) return rows;

  return asArray<string>(drugdb.activity_molecule_ids).slice(0, 5).map((moleculeId) => ({
    drug_name: moleculeId,
      molecule_chembl_id: moleculeId,
      current_indications: [],
      mechanism: `Derived from ChEMBL target activity evidence relevant to ${query}.`,
      target_symbol: "",
      max_phase: 0,
      is_approved: false,
      source: "chembl_activity" as const
  }));
}

function buildHypothesisMap(repurposing: JsonRecord): Map<string, JsonRecord> {
  return new Map(
    asArray<JsonRecord>(repurposing.hypotheses)
      .map((item) => [asString(item.drug_name).toUpperCase(), item] as const)
      .filter(([drugName]) => Boolean(drugName))
  );
}

function buildEvidenceMap(evidence: JsonRecord): Map<string, EvidenceScore> {
  return new Map(
    asArray<JsonRecord>(evidence.scores)
      .map((item) => {
        const breakdown = asRecord(item.breakdown);
        const score: EvidenceScore = {
          drug_name: asString(item.drug_name),
          molecule_chembl_id: asString(item.molecule_chembl_id),
          score: asNumber(item.score),
          breakdown: {
            literature_support: asNumber(breakdown.literature_support),
            mechanism_overlap: asNumber(breakdown.mechanism_overlap),
            clinical_evidence: asNumber(breakdown.clinical_evidence),
            safety_profile: asNumber(breakdown.safety_profile),
            genetic_support: asNumber(breakdown.genetic_support)
          },
          supporting_pmids: asArray<string>(item.supporting_pmids).filter(Boolean),
          nct_ids: asArray<string>(item.nct_ids).filter(Boolean),
          rationale: asString(item.rationale)
        };
        return [score.drug_name.toUpperCase(), score] as const;
      })
      .filter(([drugName]) => Boolean(drugName))
  );
}

function isNoHitEvaluatorDecision(evaluator: JsonRecord): boolean {
  const decision = asString(evaluator.decision).toLowerCase();
  return decision === "completed with no hit";
}

function pickSupportingPmids(cards: LiteraturePaperCard[], limit = 3): string[] {
  return cards
    .filter((card) => card.pmid)
    .sort((left, right) => right.attention - left.attention || right.year - left.year)
    .slice(0, limit)
    .map((card) => card.pmid);
}

function computeLiteratureSupport(cards: LiteraturePaperCard[]): number {
  if (cards.length === 0) return 0;

  const evidencePoints = cards.reduce((sum, card) => {
    const evidenceWeight =
      card.evidence_strength === "high" ? 4 :
      card.evidence_strength === "medium" ? 2.5 :
      1;
    const maturityWeight =
      card.clinical_maturity === "high" ? 2.5 :
      card.clinical_maturity === "medium" ? 1.5 :
      0.5;
    const recencyWeight =
      card.year >= 2023 ? 1.5 :
      card.year >= 2020 ? 1 :
      card.year >= 2016 ? 0.5 :
      0;
    const attentionWeight = Math.min(card.attention / 40, 2.5);
    const riskPenalty =
      card.risk_level === "high" ? 2 :
      card.risk_level === "medium" ? 0.75 :
      0;
    return sum + evidenceWeight + maturityWeight + recencyWeight + attentionWeight - riskPenalty;
  }, 0);

  const diversityBonus = new Set(cards.map((card) => card.study_type)).size >= 2 ? 1.5 : 0;
  return clamp(Math.round(evidencePoints + diversityBonus), 0, 30);
}

function computeMechanismOverlap(context: DrugContext, cards: LiteraturePaperCard[]): number {
  const indicationBreadth = Math.min(context.current_indications.length, 4);
  const approvalBonus = context.is_approved ? 2 : context.max_phase >= 2 ? 1 : 0;
  const targetBonus = context.target_symbol ? 2 : 0;
  const humanSignalBonus = cards.some((card) => card.population === "human") ? 2 : 0;
  const reviewPenalty = cards.length > 0 && cards.every((card) => card.study_type === "review") ? 2 : 0;

  const base =
    context.source === "opentargets"
      ? 16 + indicationBreadth * 2 + targetBonus + approvalBonus + humanSignalBonus
      : 9 + indicationBreadth + targetBonus + approvalBonus;

  return clamp(base - reviewPenalty, 0, 30);
}

function scoreClinicalEvidence(context: DrugContext, cards: LiteraturePaperCard[]): number {
  const highMaturityCount = cards.filter((card) => card.clinical_maturity === "high").length;
  const mediumMaturityCount = cards.filter((card) => card.clinical_maturity === "medium").length;
  const humanPopulationCount = cards.filter((card) => card.population === "human").length;
  const randomizedCount = cards.filter((card) => card.study_type.includes("randomized") || card.study_type.includes("phase")).length;

  let score =
    context.max_phase >= 4 ? 17 :
    context.max_phase >= 3 ? 14 :
    context.max_phase >= 2 ? 11 :
    context.max_phase >= 1 ? 8 :
    3;

  score += highMaturityCount * 2.5;
  score += mediumMaturityCount * 1.25;
  score += Math.min(humanPopulationCount, 2) * 1.25;
  score += Math.min(randomizedCount, 2) * 0.75;
  return clamp(Math.round(score), 0, 25);
}

function scoreSafetyProfile(context: DrugContext, cards: LiteraturePaperCard[]): number {
  const combined = cards.map((card) => `${card.title} ${card.abstract}`).join(" ").toLowerCase();
  let score = context.max_phase >= 4 ? 13 : context.max_phase >= 1 ? 10 : 7;
  if (
    combined.includes("toxicity") ||
    combined.includes("adverse event") ||
    combined.includes("microhemorrhage") ||
    combined.includes("safety concern")
  ) {
    score -= 4;
  }
  if (cards.some((card) => card.risk_level === "high")) score -= 3;
  if (cards.some((card) => card.risk_level === "medium")) score -= 1;
  return clamp(score, 0, 15);
}

function buildEvidenceScore(context: DrugContext, cards: LiteraturePaperCard[]): EvidenceScore {
  const supportingPmids = pickSupportingPmids(cards, 3);
  const selectedCards = supportingPmids.map((pmid) => cards.find((card) => card.pmid === pmid)).filter(Boolean) as LiteraturePaperCard[];
  const literatureSupport = computeLiteratureSupport(selectedCards);
  const mechanismOverlap = computeMechanismOverlap(context, selectedCards);
  const clinicalEvidence = scoreClinicalEvidence(context, selectedCards);
  const safetyProfile = scoreSafetyProfile(context, selectedCards);
  const score = clamp(literatureSupport + mechanismOverlap + clinicalEvidence + safetyProfile, 0, 100);
  const rationaleParts = [
    context.source === "opentargets"
      ? "Supported by OpenTargets disease-target-drug linkage."
      : "Supported by ChEMBL activity evidence without a disease-linked OpenTargets row.",
    supportingPmids.length > 0
      ? `Literature support anchored in PMID ${supportingPmids.join(", ")}.`
      : "No PMID-level support was available in this run.",
    context.max_phase >= 1
      ? `Clinical maturity is improved by max clinical stage ${context.max_phase}.`
      : "Clinical maturity remains limited because no human development stage was recovered.",
    safetyProfile <= 7
      ? "Safety score is conservative because the available evidence includes limited or risk-flagged support."
      : "Safety score remains moderate because no major integrity or toxicity signal dominated the supporting papers."
  ];

  return {
    drug_name: context.drug_name,
    molecule_chembl_id: context.molecule_chembl_id,
    score,
    breakdown: {
      literature_support: literatureSupport,
      mechanism_overlap: mechanismOverlap,
      clinical_evidence: clinicalEvidence,
      safety_profile: safetyProfile,
      genetic_support: 0
    },
    supporting_pmids: supportingPmids,
    nct_ids: [],
    rationale: sentence(rationaleParts.join(" "))
  };
}

function diseaseMatchesCombined(diseaseLower: string, combined: string): boolean {
  if (!diseaseLower) return false;
  if (combined.includes(diseaseLower)) return true;
  for (const [fragment, abbreviations] of Object.entries(DISEASE_ABBREVIATIONS)) {
    if (!diseaseLower.includes(fragment)) continue;
    for (const abbreviation of abbreviations) {
      const pattern = new RegExp(`\\b${abbreviation.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\b`, "i");
      if (pattern.test(combined)) return true;
    }
  }
  return false;
}

function inferRepurposingNote(diseaseName: string, currentUse: string, context: DrugContext): [boolean, string] {
  const diseaseLower = diseaseName.toLowerCase();
  const combined = sentence(`${context.current_indications.join(" ")} ${currentUse}`).toLowerCase();
  if (diseaseMatchesCombined(diseaseLower, combined)) {
    return [
      true,
      `This appears to be a known ${diseaseName} asset rather than a clean cross-indication repurposing case. Interpret the ranking as asset triage, not novel repositioning.`
    ];
  }
  if (context.is_approved) {
    return [
      false,
      "This is a cross-indication repurposing candidate with approved or late-stage exposure outside the queried disease."
    ];
  }
  if (context.max_phase >= 1) {
    return [
      false,
      "This is a clinically exposed but not clearly approved candidate outside the queried disease; translational risk remains material."
    ];
  }
  return [
    false,
    "This is an early-stage or investigational candidate, so repurposing value depends more on mechanism quality than on prior human exposure."
  ];
}

function buildEvidenceQualityNote(pmids: string[], literatureMap: Record<string, LiteraturePaperCard>): string {
  const papers = pmids.map((pmid) => literatureMap[pmid]).filter(Boolean);
  if (papers.length === 0) return "";
  const highStrength = papers.filter((paper) => paper.evidence_strength === "high").length;
  const mediumStrength = papers.filter((paper) => paper.evidence_strength === "medium").length;
  const humanMaturity = papers.filter((paper) => paper.clinical_maturity !== "low").length;
  if (highStrength > 0) {
    return `Support includes ${highStrength} higher-tier paper(s), with ${humanMaturity} study/studies showing at least human or mixed-clinical maturity.`;
  }
  if (mediumStrength > 0) {
    return `Support is mostly mid-tier literature: ${mediumStrength} mid-tier paper(s) and ${humanMaturity} study/studies with at least human or mixed-clinical maturity.`;
  }
  return "Support is mostly lower-tier literature, so the ranking depends more on mechanism coherence than on direct causal evidence.";
}

function buildEvidenceTrace(pmids: string[], literatureMap: Record<string, LiteraturePaperCard>): string {
  const papers = pmids
    .map((pmid) => literatureMap[pmid])
    .filter(Boolean) as LiteraturePaperCard[];
  const hasFullTextVerification = papers.some((paper) => paper.content_level === "full_text");
  return hasFullTextVerification
    ? "Prioritized literature screening with targeted source verification"
    : "Prioritized literature screening";
}

function buildGeneticEvidenceSummary(pathway: JsonRecord, userType: "pharma" | "researcher" | "doctor"): string {
  const geneticItems = asArray<JsonRecord>(pathway.genetic_evidence);
  if (geneticItems.length === 0) return "";
  const first = geneticItems[0] ? asRecord(geneticItems[0]) : {};
  const genes = asArray<string>(first.prioritized_genes).filter(Boolean).slice(0, 5);
  const support = asNumber(first.genetic_support_score);
  if (genes.length === 0) {
    return userType === "doctor"
      ? `We reviewed disease-biology signals, but this run did not surface a short list of genes worth highlighting here.`
      : `We reviewed disease-biology signals, but this run did not produce a short list of priority genes.`;
  }

  const geneList = genes.join(", ");
  if (userType === "doctor") {
    return sentence(
      `We reviewed disease-biology signals linked to this condition. The genes that stood out most were ${geneList}. ` +
        `In practical terms, this makes candidates connected to these pathways more relevant for follow-up, but it does not prove that any one gene or drug is the cause. Genetic support score: ${support.toFixed(3)}.`
    );
  }
  if (userType === "pharma") {
    return sentence(
      `We reviewed disease-biology signals linked to this condition. The strongest recurring genes in this pass were ${geneList}. ` +
        `Candidates linked to these genes should rank higher for follow-up, although this signal does not establish causality. Genetic support score: ${support.toFixed(3)}.`
    );
  }
  return sentence(
    `We reviewed disease-biology signals linked to this condition. The genes that stood out most were ${geneList}. ` +
      `This makes candidates connected to these pathways more relevant for follow-up, but it does not prove that any one gene or drug is the cause. Genetic support score: ${support.toFixed(3)}.`
  );
}

function buildTrialContexts(pathway: JsonRecord): TrialContext[] {
  return asArray<JsonRecord>(pathway.clinical_trials).map((trial) => ({
    nct_id: asString(trial.nct_id),
    title: asString(trial.title),
    phase: asString(trial.phase),
    status: asString(trial.status),
    drugs: asArray<string>(trial.drugs).filter(Boolean)
  }));
}

function buildPathwayAnchors(pathway: JsonRecord): string[] {
  return asArray<JsonRecord>(pathway.pathways)
    .map((item) => asString(item.pathway_name))
    .filter(Boolean)
    .slice(0, 8);
}

interface GeneticAssessment {
  score: number;
  tier: "Tier 1" | "Tier 2" | "Tier 3";
  direction: "supportive" | "missing" | "contradictory";
  provenance: string;
  penalty_reason: string;
  summary: string;
}

interface DiseaseLinkAssessment {
  penalty: number;
  flags: string[];
  summary: string;
}

function assessGeneticSupport(input: {
  context: DrugContext;
  pathway: JsonRecord;
  hypothesis: JsonRecord;
  critic?: RedTeamCritique;
}): GeneticAssessment {
  const first = asRecord(asArray<JsonRecord>(input.pathway.genetic_evidence)[0]);
  const source = asString(first.source_gwas) || "pathway-stage disease-biology sources";
  const note = asString(first.note);
  const support = asNumber(first.genetic_support_score);
  const genes = asArray<string>(first.prioritized_genes).map((gene) => gene.toUpperCase()).filter(Boolean).slice(0, 8);
  if (genes.length === 0) {
    return {
      score: 0,
      tier: "Tier 3",
      direction: "missing",
      provenance: "No disease-gene shortlist was available in this run.",
      penalty_reason: "",
      summary: "No genetic evidence block was available, so the ranking stays literature- and mechanism-led."
    };
  }

  const haystack = sentence(
    `${input.context.drug_name} ${input.context.mechanism} ${input.context.current_indications.join(" ")} ` +
    `${asString(input.hypothesis.mechanism_overlap)} ${asString(input.hypothesis.mechanism_hypothesis)} ` +
    `${asString(input.hypothesis.biomarker_link)} ${asString(input.hypothesis.subgroup_link)}`
  ).toUpperCase();
  const matchedGenes = genes.filter((gene) => haystack.includes(gene));
  const directTarget = asString(input.context.target_symbol).toUpperCase();
  const directTargetMatch = directTarget ? genes.includes(directTarget) : false;
  const contradictionText = sentence(
    `${input.critic?.translation_risk ?? ""} ${input.critic?.evidence_confounders ?? ""} ${input.critic?.disease_specific_failure ?? ""}`
  ).toLowerCase();
  const explicitContradiction =
    contradictionText.includes("contradict") ||
    contradictionText.includes("opposes the disease signal") ||
    contradictionText.includes("runs against the disease biology");

  if (explicitContradiction) {
    return {
      score: -10,
      tier: "Tier 3",
      direction: "contradictory",
      provenance: `${source}. ${note || "The current critic layer flagged a disease-biology contradiction."}`.trim(),
      penalty_reason: "A disease-biology contradiction was flagged in the current evidence pass.",
      summary: "The available disease-biology readout points against the proposed mechanism, so a genetic penalty was applied."
    };
  }

  if (directTargetMatch && support >= 0.45) {
    return {
      score: 10,
      tier: "Tier 1",
      direction: "supportive",
      provenance: `${source}. Direct target overlap with disease-linked gene ${directTarget}.`.trim(),
      penalty_reason: "",
      summary: `The candidate directly targets disease-linked gene ${directTarget}, so a full genetic bonus was applied.`
    };
  }

  if (matchedGenes.length > 0 && support >= 0.45) {
    return {
      score: 5,
      tier: "Tier 2",
      direction: "supportive",
      provenance: `${source}. Mechanism or pathway overlap was present, including ${matchedGenes.slice(0, 3).join(", ")}.`.trim(),
      penalty_reason: "",
      summary: `The candidate overlaps with disease-linked biology around ${matchedGenes.slice(0, 3).join(", ")}, so a partial genetic bonus was applied.`
    };
  }

  if (matchedGenes.length > 0 || support >= 0.45) {
    return {
      score: 2,
      tier: "Tier 2",
      direction: "supportive",
      provenance: `${source}. Only a weak disease-biology link was present in this run${matchedGenes.length > 0 ? `, touching ${matchedGenes.slice(0, 2).join(", ")}` : ""}.`.trim(),
      penalty_reason: "",
      summary: "A weak disease-biology link was present, so only a small genetic bonus was applied."
    };
  }

  return {
    score: 0,
    tier: "Tier 3",
    direction: "missing",
    provenance: `${source}. Genetic signal was present at the disease level, but it did not clearly connect to this candidate in the current run.`.trim(),
    penalty_reason: "",
    summary: "Genetic context was available, but it stayed too indirect to change the score."
  };
}

function assessDiseaseLinkStrength(input: {
  diseaseName: string;
  context: DrugContext;
  hypothesis: JsonRecord;
  pathway: JsonRecord;
  literatureMap: Record<string, LiteraturePaperCard>;
  supportingPmids: string[];
  failureEvidenceBasis: "direct" | "indirect" | "speculative";
}): DiseaseLinkAssessment {
  const papers = input.supportingPmids
    .map((pmid) => input.literatureMap[pmid])
    .filter(Boolean)
    .map((paper) => ({
      title: paper.title,
      abstract: paper.abstract,
      content_level: paper.content_level,
      evidence_snippets: []
    }));
  const genes = asArray<string>(asRecord(asArray<JsonRecord>(input.pathway.genetic_evidence)[0]).prioritized_genes)
    .map((gene) => gene.toUpperCase())
    .filter(Boolean)
    .slice(0, 8);
  const mechanismText = sentence(
    [
      input.context.mechanism,
      input.context.target_symbol,
      asString(input.hypothesis.mechanism_hypothesis),
      asString(input.hypothesis.mechanism_overlap),
      asString(input.hypothesis.rationale),
      asString(input.hypothesis.biomarker_link),
      asString(input.hypothesis.subgroup_link)
    ].join(" ")
  );
  const candidateMentionCount = papers.filter((paper) => {
    const text = paperEvidenceText(paper);
    return textIncludesToken(text, input.context.drug_name) || textIncludesToken(text, input.context.molecule_chembl_id);
  }).length;
  const diseaseLower = input.diseaseName.toLowerCase();
  const diseaseMentionCount = papers.filter((paper) => diseaseMatchesCombined(diseaseLower, paperEvidenceText(paper).toLowerCase())).length;
  const verifiedCount = papers.filter((paper) => paperHasTargetedSourceVerification(paper)).length;
  const directTarget = asString(input.context.target_symbol).toUpperCase();
  const directTargetMatch = directTarget ? genes.includes(directTarget) : false;
  const mechanismGeneMatches = genes.filter((gene) => textIncludesToken(mechanismText, gene));
  const allPreclinical = papers.length > 0 && papers.every((paper) => inferClinicalMaturity(paper.title, paper.abstract) === "low");

  if (candidateMentionCount > 0 && (directTargetMatch || mechanismGeneMatches.length > 0 || diseaseMentionCount > 0)) {
    return {
      penalty: 0,
      flags: [],
      summary: "Candidate-specific literature support was present, so no additional disease-link penalty was applied."
    };
  }

  if (candidateMentionCount > 0) {
    return {
      penalty: 3,
      flags: ["indirect_disease_link"],
      summary: "Candidate-specific mention was present, but the disease bridge remained indirect, so a small disease-link penalty was applied."
    };
  }

  let penalty = 0;
  const flags = ["disease_context_only_evidence"];
  let summary = "";

  if (directTargetMatch) {
    penalty = 4;
    flags.push("target_only_bridge");
    summary = `No supporting paper directly mentioned ${input.context.drug_name}, so the candidate is being carried mainly by target-level overlap with disease-linked gene ${directTarget}.`;
  } else if (mechanismGeneMatches.length > 0) {
    penalty = 10;
    flags.push("weak_disease_link");
    summary = `No supporting paper directly mentioned ${input.context.drug_name}; the remaining bridge is only indirect mechanism overlap around ${mechanismGeneMatches.slice(0, 2).join(", ")}.`;
  } else {
    penalty = 14;
    flags.push("missing_disease_link");
    summary = `No supporting paper directly mentioned ${input.context.drug_name}, and no gene-level bridge to ${input.diseaseName} was recovered in this run.`;
  }

  if (verifiedCount === 0) {
    penalty += 2;
    flags.push("unverified_candidate_bridge");
  }
  if (allPreclinical) {
    penalty += 2;
    flags.push("preclinical_only_bridge");
  }
  if (input.failureEvidenceBasis === "speculative") {
    penalty += 2;
    flags.push("speculative_bridge");
  }

  return {
    penalty,
    flags,
    summary: sentence(`${summary} Disease-context evidence alone should not rank like candidate-specific validation.`)
  };
}

function normalizeEvidenceScore(input: {
  evidence: EvidenceScore;
  context: DrugContext;
  pathway: JsonRecord;
  hypothesis: JsonRecord;
  critic?: RedTeamCritique;
}): EvidenceScore & { genetic_assessment: GeneticAssessment } {
  const literatureSupport = clamp(input.evidence.breakdown.literature_support, 0, 30);
  const mechanismOverlap = clamp(input.evidence.breakdown.mechanism_overlap, 0, 30);
  const clinicalEvidence = clamp(Math.round((input.evidence.breakdown.clinical_evidence / 25) * 20), 0, 20);
  const safetyProfile = clamp(Math.round((input.evidence.breakdown.safety_profile / 15) * 10), 0, 10);
  const geneticAssessment = assessGeneticSupport({
    context: input.context,
    pathway: input.pathway,
    hypothesis: input.hypothesis,
    critic: input.critic
  });
  const total = clamp(
    literatureSupport + mechanismOverlap + clinicalEvidence + safetyProfile + geneticAssessment.score,
    0,
    100
  );

  return {
    ...input.evidence,
    score: total,
    breakdown: {
      literature_support: literatureSupport,
      mechanism_overlap: mechanismOverlap,
      clinical_evidence: clinicalEvidence,
      safety_profile: safetyProfile,
      genetic_support: geneticAssessment.score
    },
    rationale: sentence(`${input.evidence.rationale} ${geneticAssessment.summary}`),
    genetic_assessment: geneticAssessment
  };
}

function buildCausalSupport(context: DrugContext, pathway: JsonRecord, hypothesis: JsonRecord): string {
  const geneticItems = asArray<JsonRecord>(pathway.genetic_evidence);
  if (geneticItems.length === 0) {
    return "No direct genetic support in this run; ranking remains literature- and mechanism-led.";
  }
  const first = asRecord(geneticItems[0]);
  const genes = asArray<string>(first.prioritized_genes).map((gene) => gene.toUpperCase()).slice(0, 8);
  const haystack = `${context.drug_name} ${context.mechanism} ${context.current_indications.join(" ")} ${asString(hypothesis.mechanism_overlap)} ${asString(hypothesis.mechanism_hypothesis)}`.toUpperCase();
  const matched = genes.filter((gene) => gene && haystack.includes(gene));
  if (matched.length > 0) {
    return `This candidate overlaps with disease-biology signals seen in ${matched.slice(0, 3).join(", ")}, but that still does not prove a direct causal effect.`;
  }
  const support = asNumber(first.genetic_support_score);
  return support > 0
    ? `This ranking has some disease-biology support, but no direct gene-level link was established for ${context.drug_name}.`
    : "No direct genetic support in this run; ranking remains literature- and mechanism-led.";
}

function buildCandidateSpecificRisk(context: DrugContext, evidence: EvidenceScore, literatureMap: Record<string, LiteraturePaperCard>, supportingPmids: string[]): string {
  const papers = supportingPmids.map((pmid) => literatureMap[pmid]).filter(Boolean);
  const years = papers.map((paper) => paper.year).filter((year) => year > 0);
  const newestYear = years.length > 0 ? Math.max(...years) : 0;
  const mostlyPreclinical = papers.length > 0 && papers.every((paper) => paper.clinical_maturity === "low");
  if (mostlyPreclinical) {
    return "Most supporting papers are still preclinical, so disease translation remains uncertain.";
  }
  if (newestYear > 0 && newestYear < 2020) {
    return "The support base is not especially recent, which raises the risk that the signal is stale or incomplete.";
  }
  if (evidence.breakdown.safety_profile <= 7) {
    return "Safety interpretation remains cautious because the current literature includes risk or quality flags.";
  }
  if (context.current_indications.length === 0) {
    return "Mechanism fit is stronger than indication-level validation in the current data window.";
  }
  return "The current signal is still research-stage and could reflect indication adjacency more than disease-specific efficacy.";
}

function severityRank(value: "low" | "medium" | "high"): number {
  if (value === "high") return 2;
  if (value === "medium") return 1;
  return 0;
}

function deriveConfidence(input: {
  hypothesis: JsonRecord;
  adjustedScore: number;
  failureSeverity: "low" | "medium" | "high";
  geneticTier: "Tier 1" | "Tier 2" | "Tier 3";
}): "low" | "medium" | "high" {
  const explicit = asString(input.hypothesis.confidence);
  let rank =
    explicit === "high" ? 2 :
    explicit === "medium" ? 1 :
    explicit === "low" ? 0 :
    input.adjustedScore >= 75 ? 2 :
    input.adjustedScore >= 55 ? 1 :
    0;

  rank -= severityRank(input.failureSeverity);
  if (input.geneticTier === "Tier 1") rank += 1;
  if (input.geneticTier === "Tier 3") rank -= 1;

  return rank >= 2 ? "high" : rank >= 1 ? "medium" : "low";
}

function buildConfidenceDrivers(input: {
  evidence: EvidenceScore;
  geneticAssessment: GeneticAssessment;
  failureSeverity: "low" | "medium" | "high";
}): ReportTopCandidate["confidence_drivers"] {
  const evidenceStrength =
    input.evidence.breakdown.literature_support >= 20 ? "strong" :
    input.evidence.breakdown.literature_support >= 12 ? "moderate" :
    "limited";
  const geneticSupport =
    input.geneticAssessment.score >= 10 ? "strong" :
    input.geneticAssessment.score >= 5 ? "moderate" :
    input.geneticAssessment.score > 0 ? "weak" :
    "weak";
  const clinicalMaturity =
    input.evidence.breakdown.clinical_evidence >= 14 ? "high" :
    input.evidence.breakdown.clinical_evidence >= 9 ? "medium" :
    "low";

  const reasons: string[] = [];
  if (input.failureSeverity === "high") reasons.push("high failure risk");
  else if (input.failureSeverity === "medium") reasons.push("meaningful red-team risk");
  if (clinicalMaturity === "low") reasons.push("low clinical validation");
  else if (clinicalMaturity === "medium") reasons.push("only moderate clinical maturity");
  if (evidenceStrength === "limited") reasons.push("thin literature support");
  if (geneticSupport === "weak") reasons.push("weak disease-biology specificity");

  const summary =
    reasons.length > 0
      ? `Confidence is limited by ${reasons.slice(0, 2).join(" and ")}.`
      : input.geneticAssessment.score >= 10
        ? "Confidence is helped by direct disease-biology alignment."
        : "Confidence is supported by a balanced evidence profile in this run.";

  return {
    evidence_strength: evidenceStrength,
    genetic_support: geneticSupport,
    red_team_severity: input.failureSeverity,
    clinical_maturity: clinicalMaturity,
    summary
  };
}

function computeAdjustedScore(
  evidence: EvidenceScore,
  knownDiseaseAsset: boolean,
  negativeEvidence: string,
  failureSeverity: "low" | "medium" | "high"
): [number, string[]] {
  let adjusted = evidence.score;
  const flags: string[] = [];
  const lowered = negativeEvidence.toLowerCase();

  if (knownDiseaseAsset) {
    adjusted -= 25;
    flags.push("known_disease_asset");
  }
  if (
    lowered.includes("failed to") ||
    lowered.includes("did not meet") ||
    lowered.includes("discontinued") ||
    lowered.includes("lack of efficacy")
  ) {
    adjusted -= 10;
    flags.push("negative_clinical_signal");
  }
  if (
    lowered.includes("aria") ||
    lowered.includes("toxicity") ||
    lowered.includes("adverse event") ||
    lowered.includes("microhemorrhage") ||
    lowered.includes("safety concern")
  ) {
    adjusted -= 5;
    flags.push("safety_risk");
  }
  if (evidence.breakdown.clinical_evidence <= 5) {
    adjusted -= 5;
    flags.push("weak_clinical_support");
  }
  if (failureSeverity === "high") {
    adjusted -= 5;
    flags.push("high_failure_risk");
  } else if (failureSeverity === "medium") {
    adjusted -= 2;
    flags.push("moderate_failure_risk");
  }
  return [Math.max(0, adjusted), flags];
}

function buildCurrentUse(context: DrugContext): string {
  if (context.current_indications.length > 0) {
    return `Currently used or clinically studied in ${context.current_indications.slice(0, 3).join(", ")}.`;
  }
  if (context.is_approved || context.max_phase >= 1) {
    return "Approved or clinically studied in other indications.";
  }
  return "Current use was not recovered in the available source data for this run.";
}

function isOpaqueCandidateId(value?: string): boolean {
  return /^CHEMBL\d+$/i.test(String(value || "").trim());
}

function isChemicalStyleName(value?: string): boolean {
  const normalized = String(value || "").trim();
  if (!normalized || isOpaqueCandidateId(normalized)) return false;
  const longEnough = normalized.length >= 45;
  const punctuationHeavy = /[\[\]\(\)\-]/.test(normalized);
  const formulaLike = /\b(?:yl|amide|benz|methyl|phenyl|sulfonyl|oxazol)\b/i.test(normalized);
  return longEnough && punctuationHeavy && formulaLike;
}

function isSyntheticFallbackCandidateName(value?: string): boolean {
  return /^Unnamed .+\(CHEMBL\d+\)$/i.test(String(value || "").trim());
}

function inferCandidateAnchorLabel(input: {
  context: DrugContext;
  hypothesis?: JsonRecord;
  pathway?: JsonRecord;
}): string {
  const haystack = sentence(
    [
      input.context.drug_name,
      input.context.mechanism,
      input.context.target_symbol,
      input.context.current_indications.join(" "),
      asString(input.hypothesis?.mechanism_hypothesis),
      asString(input.hypothesis?.mechanism_overlap),
      asString(input.hypothesis?.rationale),
      asString(input.hypothesis?.biomarker_link),
      asString(input.hypothesis?.subgroup_link)
    ].join(" ")
  );

  const patterns: Array<[RegExp, string]> = [
    [/\bTERT\b|\btelomere\b|\bRTEL1\b|\bPARN\b/i, "telomere-linked"],
    [/\bCFTR\b/i, "CFTR-linked"],
    [/\bSFTPA2\b|\bsurfactant\b/i, "surfactant-linked"],
    [/\bDNA repair\b|\bPARP\b|\bATM\b|\bATR\b/i, "DNA-repair-linked"],
    [/\bβ-catenin\b|\bbeta-catenin\b|\bWnt\b/i, "Wnt/beta-catenin-linked"],
    [/\bTGF-?beta\b|\bTGFB\b|\bintegrin\b/i, "fibrosis-pathway-linked"],
    [/\binflammation\b|\bNF-?kB\b|\bNLRP3\b/i, "inflammation-linked"],
    [/\bvascular\b|\bangiogenesis\b/i, "vascular-remodeling-linked"],
    [/\bepithelial trafficking\b|\btrafficking\b/i, "epithelial-trafficking-linked"],
    [/\boxidative stress\b|\bNRF2\b/i, "oxidative-stress-linked"],
    [/\bmitochond/i, "mitochondria-linked"]
  ];

  for (const [pattern, label] of patterns) {
    if (pattern.test(haystack)) return label;
  }

  if (input.context.target_symbol) return `${input.context.target_symbol}-linked`;

  const pathwayAnchors = buildPathwayAnchors(input.pathway ?? {});
  if (pathwayAnchors[0]) {
    return `${pathwayAnchors[0].replace(/\s+pathway$/i, "").trim()}-linked`;
  }

  return "investigational";
}

function buildDisplayCandidateName(input: {
  context: DrugContext;
  hypothesis?: JsonRecord;
  pathway?: JsonRecord;
}): string {
  const rawName = input.context.drug_name.trim();
  const moleculeId = input.context.molecule_chembl_id.trim();

  if (moleculeId && (isOpaqueCandidateId(rawName) || isChemicalStyleName(rawName))) {
    return moleculeId;
  }
  if (!isOpaqueCandidateId(rawName)) return rawName;
  const anchor = inferCandidateAnchorLabel(input);
  if (!anchor || anchor === "investigational") return rawName;
  return `${rawName} (${anchor})`;
}

function replaceCandidateIdentifiers(text: string, candidate: Pick<ReportTopCandidate, "drug_name" | "molecule_chembl_id" | "display_name">): string {
  if (!text) return "";
  const shouldReplace =
    Boolean(candidate.display_name) &&
    (isOpaqueCandidateId(candidate.drug_name) ||
      (Boolean(candidate.molecule_chembl_id) && isChemicalStyleName(candidate.drug_name) && candidate.display_name !== candidate.drug_name));
  if (!shouldReplace) return text;

  let result = text;
  const identifiers = [candidate.drug_name, candidate.molecule_chembl_id].filter(Boolean);
  for (const identifier of identifiers) {
    result = result.replace(new RegExp(`\\b${escapeRegExp(identifier)}\\b`, "gi"), candidate.display_name);
  }
  return sentence(result);
}

function inferMechanismCluster(candidate: Pick<ReportTopCandidate, "display_name" | "drug_name" | "mechanism_hypothesis" | "mechanism_overlap" | "causal_support" | "biomarker_link" | "subgroup_link">): string {
  const haystack = sentence(
    [
      candidate.display_name,
      candidate.drug_name,
      candidate.mechanism_hypothesis,
      candidate.mechanism_overlap,
      candidate.causal_support,
      candidate.biomarker_link,
      candidate.subgroup_link
    ].join(" ")
  ).toLowerCase();

  const clusters: Array<[RegExp, string]> = [
    [/\bcftr\b/, "cftr-axis"],
    [/\btert\b|\btelomere\b|\brtel1\b|\bparn\b/, "telomere-maintenance"],
    [/\bdna repair\b|\batm\b|\batr\b|\bparp\b/, "dna-repair"],
    [/\bsftpa2\b|\bsurfactant\b/, "surfactant-biology"],
    [/\bbeta-catenin\b|\bβ-catenin\b|\bwnt\b/, "wnt-beta-catenin"],
    [/\btgf-?beta\b|\btgfb\b|\bintegrin\b|\bfibrosis\b/, "fibrosis-remodeling"],
    [/\binflammation\b|\bnf-?kb\b|\bnlrp3\b/, "inflammation"],
    [/\bvascular\b|\bangiogenesis\b/, "vascular-remodeling"],
    [/\bepithelial trafficking\b|\btrafficking\b/, "epithelial-trafficking"],
    [/\bmitochond/i, "mitochondrial-stress"],
    [/\boxidative stress\b|\bnrf2\b/, "oxidative-stress"]
  ];

  for (const [pattern, label] of clusters) {
    if (pattern.test(haystack)) return label;
  }

  return isOpaqueCandidateId(candidate.drug_name) ? "opaque-investigational" : candidate.display_name.toLowerCase();
}

function inferCommonFailurePattern(candidate: Pick<ReportTopCandidate, "negative_evidence" | "false_positive_risk" | "failure_mode">): string {
  const haystack = sentence(
    [candidate.negative_evidence, candidate.false_positive_risk, candidate.failure_mode].join(" ")
  ).toLowerCase();

  if (
    haystack.includes("no mechanistic link") ||
    haystack.includes("lack direct links") ||
    haystack.includes("not affect") ||
    haystack.includes("does not affect") ||
    haystack.includes("no shared downstream")
  ) {
    return "mechanism relevance without disease-central proof";
  }
  if (haystack.includes("biomarker") || haystack.includes("clinical") || haystack.includes("human evidence")) {
    return "limited disease-specific validation";
  }
  if (haystack.includes("safety") || haystack.includes("toxicity") || haystack.includes("adverse")) {
    return "translation risk from safety or exposure";
  }
  return "general translation uncertainty";
}

function applyMechanismDiversity(candidates: ReportTopCandidate[]): ReportTopCandidate[] {
  const clusterCounts = new Map<string, number>();
  const penalized = candidates
    .map((candidate) => {
      const cluster = inferMechanismCluster(candidate);
      const count = clusterCounts.get(cluster) ?? 0;
      clusterCounts.set(cluster, count + 1);
      const redundancyPenalty = count > 0 ? Math.min(8, 4 + count * 2) : 0;
      const adjustedScoreBase = candidate.adjusted_score ?? candidate.total_score ?? 0;
      const rankingFlags = [...candidate.ranking_flags];
      if (redundancyPenalty > 0) rankingFlags.push("mechanistic_redundancy_penalty");
      return {
        ...candidate,
        mechanism_cluster: cluster,
        common_failure_pattern: inferCommonFailurePattern(candidate),
        adjusted_score: Math.max(0, adjustedScoreBase - redundancyPenalty),
        ranking_flags: rankingFlags
      };
    })
    .sort(
      (left, right) =>
        (right.adjusted_score ?? right.total_score ?? 0) - (left.adjusted_score ?? left.total_score ?? 0) ||
        left.display_name.localeCompare(right.display_name)
    );

  const selected: ReportTopCandidate[] = [];
  const seenClusters = new Set<string>();

  for (const candidate of penalized) {
    if (seenClusters.has(candidate.mechanism_cluster)) continue;
    selected.push(candidate);
    seenClusters.add(candidate.mechanism_cluster);
  }

  return selected;
}

function isWeakPlaceholderCandidate(candidate: ReportTopCandidate): boolean {
  const adjustedScore = candidate.adjusted_score ?? candidate.total_score ?? 0;
  const placeholderMechanism = candidate.mechanism_overlap.toLowerCase().includes("disease-linked pathway biology");
  const opaqueIdentity =
    isOpaqueCandidateId(candidate.drug_name) ||
    isSyntheticFallbackCandidateName(candidate.drug_name) ||
    isSyntheticFallbackCandidateName(candidate.display_name);
  const missingCurrentUse = candidate.current_use.toLowerCase().includes("not recovered");
  const thinLiterature = (candidate.literature_score ?? 0) <= 8;
  const missingGeneticAnchor = (candidate.genetic_score ?? 0) <= 0;
  const activityLedCandidate = candidate.candidate_role.toLowerCase().includes("activity-led");
  const earlyResearchFit = candidate.discovery_fit.toLowerCase() === "early research fit";
  const weakClinicalSupport = candidate.ranking_flags.includes("weak_clinical_support");
  const highFailureRisk = candidate.ranking_flags.includes("high_failure_risk");
  const noClinicalMaturity = !candidate.is_approved && candidate.max_phase <= 0;
  const noKnownDiseaseAsset = candidate.known_disease_asset !== true;
  const lowConfidence = candidate.confidence === "low";

  if (adjustedScore >= 55) return false;
  if (opaqueIdentity && missingCurrentUse) return true;
  if (placeholderMechanism && missingGeneticAnchor) return true;
  if (thinLiterature && missingGeneticAnchor) return true;
  if (
    activityLedCandidate &&
    earlyResearchFit &&
    missingCurrentUse &&
    weakClinicalSupport &&
    highFailureRisk &&
    adjustedScore < 40
  ) {
    return true;
  }
  if (
    activityLedCandidate &&
    candidate.source_type === "chembl_activity" &&
    earlyResearchFit &&
    noClinicalMaturity &&
    noKnownDiseaseAsset &&
    missingCurrentUse &&
    lowConfidence &&
    weakClinicalSupport &&
    adjustedScore < 45
  ) {
    return true;
  }
  return false;
}

function shouldForceEarlyStageHypothesis(candidate: ReportTopCandidate): boolean {
  const adjustedScore = candidate.adjusted_score ?? candidate.total_score ?? 0;
  const diseaseContextOnlyEvidence = candidate.ranking_flags.includes("disease_context_only_evidence");
  const diseaseBridgeTooWeak =
    candidate.ranking_flags.includes("weak_disease_link") ||
    candidate.ranking_flags.includes("missing_disease_link");
  const speculativeEvidence = candidate.failure_evidence_basis === "speculative";

  return adjustedScore < 40 && diseaseContextOnlyEvidence && diseaseBridgeTooWeak && speculativeEvidence;
}

function hasInterpretableCandidateIdentity(candidate: ReportTopCandidate): boolean {
  if (candidate.ranking_flags.includes("opaque_identity")) return false;
  if (isWeakPlaceholderCandidate(candidate)) return false;
  if (isOpaqueCandidateId(candidate.drug_name) || isOpaqueCandidateId(candidate.display_name)) return false;
  if (isSyntheticFallbackCandidateName(candidate.display_name) || isSyntheticFallbackCandidateName(candidate.drug_name)) return false;
  return true;
}

function hasUsableMechanismAnchor(candidate: ReportTopCandidate): boolean {
  const mechanismText = sentence(
    [
      candidate.mechanism_overlap,
      candidate.mechanism_hypothesis,
      candidate.causal_support,
      candidate.biomarker_link,
      candidate.subgroup_link,
      candidate.candidate_role
    ].join(" ")
  ).toLowerCase();
  const mechanismScore = candidate.mechanism_score ?? 0;

  return mechanismScore >= 8 || (
    mechanismText.length > 0 &&
    !mechanismText.includes("derived from the available drug evidence collected") &&
    !mechanismText.includes("disease-linked pathway biology")
  );
}

function hasMinimalLiteratureSupport(candidate: ReportTopCandidate): boolean {
  return candidate.supporting_pmids.length > 0 || (candidate.literature_score ?? 0) >= 8;
}

function isEligibleForEarlyStagePromotion(candidate: ReportTopCandidate): boolean {
  const signals = [
    hasInterpretableCandidateIdentity(candidate),
    hasUsableMechanismAnchor(candidate),
    hasMinimalLiteratureSupport(candidate)
  ].filter(Boolean).length;

  const hardReject =
    candidate.ranking_flags.includes("opaque_identity") ||
    (
      !hasInterpretableCandidateIdentity(candidate) &&
      !hasMinimalLiteratureSupport(candidate) &&
      !hasUsableMechanismAnchor(candidate)
    );

  return !hardReject && signals >= 2;
}

function isEarlyStageHypothesisCandidate(candidate: ReportTopCandidate): boolean {
  if (candidate.known_disease_asset === true) return false;
  if (!isEligibleForEarlyStagePromotion(candidate)) return false;
  const adjustedScore = candidate.adjusted_score ?? candidate.total_score ?? 0;
  const lowConfidence = candidate.confidence === "low";
  const highFailureRisk = candidate.ranking_flags.includes("high_failure_risk");
  const weakClinicalSupport = candidate.ranking_flags.includes("weak_clinical_support");
  const limitedLiterature = (candidate.literature_score ?? 0) <= 10;
  const directCandidateEvidenceMissing =
    sentence(
      [
        candidate.negative_evidence,
        candidate.score_rationale,
        candidate.false_positive_risk
      ].join(" ")
    ).toLowerCase().includes("none of the supporting papers directly mention this candidate");
  if (shouldForceEarlyStageHypothesis(candidate)) return true;

  return adjustedScore >= 40 && lowConfidence && (highFailureRisk || weakClinicalSupport || limitedLiterature || directCandidateEvidenceMissing);
}

function querySuggestsMechanismAnchoredSearch(query: string): boolean {
  const normalized = sentence(query).toLowerCase();
  if (!normalized) return false;
  return [
    "resistance",
    "mutation",
    "mutant",
    "egfr",
    "alk",
    "braf",
    "mek",
    "erk",
    "mapk",
    "pik3",
    "akt",
    "mtor",
    "pathway",
    "biomarker",
    "synthetic lethal",
    "deficiency"
  ].some((term) => normalized.includes(term));
}

function filterReportableCandidates(candidates: ReportTopCandidate[], query: string): ReportTopCandidate[] {
  const mechanismAnchoredQuery = querySuggestsMechanismAnchoredSearch(query);
  return candidates.filter((candidate) => {
    if (isEarlyStageHypothesisCandidate(candidate)) return false;
    if (!isWeakPlaceholderCandidate(candidate)) return true;
    if (
      mechanismAnchoredQuery &&
      candidate.candidate_role.toLowerCase().includes("activity-led") &&
      !candidate.ranking_flags.includes("opaque_identity") &&
      (candidate.adjusted_score ?? candidate.total_score ?? 0) >= 35
    ) {
      return true;
    }
    return false;
  });
}

function filterEarlyStageHypotheses(candidates: ReportTopCandidate[]): ReportTopCandidate[] {
  return candidates
    .filter((candidate) => isEarlyStageHypothesisCandidate(candidate))
    .slice(0, 4);
}

function replaceOpaqueIdsInReportText(value: string, candidates: ReportTopCandidate[]): string {
  let result = sentence(value);
  if (!result) return "";
  for (const candidate of candidates) {
    result = replaceCandidateIdentifiers(result, candidate);
  }
  return result.replace(/\bCHEMBL\d+\b/g, "an investigational candidate");
}

function buildMainRisk(context: DrugContext, evidence: EvidenceScore): string {
  if (context.max_phase === 0) {
    return "Human efficacy and safety exposure remain limited in the currently available sources.";
  }
  if (evidence.breakdown.safety_profile <= 7) {
    return "Safety interpretation remains cautious because the current literature includes risk or quality flags.";
  }
  if (context.current_indications.length === 0) {
    return "Mechanism fit is stronger than indication-level validation in the current data window.";
  }
  return "The current signal is still research-stage and could reflect indication adjacency more than disease-specific efficacy.";
}

function buildWhyCandidate(context: DrugContext, evidence: EvidenceScore, diseaseName: string): string {
  const reasons = [
    context.source === "opentargets"
      ? `OpenTargets linked ${context.drug_name} to disease-relevant target biology for ${diseaseName}.`
      : `${context.drug_name} emerged from ChEMBL activity evidence connected to the queried biology.`,
    evidence.breakdown.literature_support >= 18
      ? "The literature pass returned multiple supportive papers with at least moderate evidence quality."
      : "The literature pass returned limited but usable support, so the ranking remains mechanism-led.",
    context.max_phase >= 1
      ? `Prior clinical exposure (max phase ${context.max_phase}) reduces translational uncertainty relative to purely preclinical options.`
      : "No clear human development stage was recovered, which keeps translational confidence modest."
  ];
  return compactNarrative(reasons.join(" "), { maxSentences: 3, maxChars: 420 });
}

function buildMechanismHypothesis(context: DrugContext, diseaseName: string): string {
  return sentence(
    `${context.drug_name} is prioritized as a ${context.source === "opentargets" ? "target-linked" : "mechanism-linked"} candidate for ${diseaseName} based on the current literature and drug-database review.`
  );
}

function buildTestablePrediction(context: DrugContext, diseaseName: string): string {
  return compactNarrative(
    `Test whether ${context.drug_name} improves ${diseaseName} relevant biomarkers or disease-readout assays before any broader translational claim.`
  , { maxSentences: 2, maxChars: 280 });
}

function buildCandidatePayload(input: {
  diseaseName: string;
  context: DrugContext;
  evidence: EvidenceScore;
  literatureMap: Record<string, LiteraturePaperCard>;
  pathway: JsonRecord;
  hypothesis?: JsonRecord;
  critic?: RedTeamCritique;
}): ReportTopCandidate {
  const hypothesis = input.hypothesis ?? {};
  const critic = input.critic;
  const currentUse = buildCurrentUse(input.context);
  const explicitKnownAsset = hypothesis.known_disease_asset === true;
  const [inferredKnownDiseaseAsset, repurposingNote] = inferRepurposingNote(input.diseaseName, currentUse, input.context);
  const knownDiseaseAsset = explicitKnownAsset || inferredKnownDiseaseAsset;
  const supportingPmids = input.evidence.supporting_pmids;
  const pathwayAnchors = buildPathwayAnchors(input.pathway);
  const trials = buildTrialContexts(input.pathway);
  const leadPathway = pathwayAnchors.find((name) => {
    const mechanismText = `${asString(hypothesis.mechanism_overlap)} ${asString(hypothesis.mechanism_hypothesis)}`.toLowerCase();
    return mechanismText.includes(name.toLowerCase());
  }) ?? pathwayAnchors[0] ?? "disease-linked pathway biology";
  const relatedTrial = trials.find((trial) =>
    trial.drugs.some((drug) => drug.toLowerCase().includes(input.context.drug_name.toLowerCase()) || input.context.drug_name.toLowerCase().includes(drug.toLowerCase()))
  );
  const mainRisk = buildCandidateSpecificRisk(input.context, input.evidence, input.literatureMap, supportingPmids);
  const normalizedEvidence = normalizeEvidenceScore({
    evidence: input.evidence,
    context: input.context,
    pathway: input.pathway,
    hypothesis,
    critic
  });
  const criticSummary = critic?.summary ?? "";
  const evidenceConfounders = critic?.evidence_confounders ?? "";
  const diseaseSpecificFailure = critic?.disease_specific_failure ?? "";
  const failureMode = critic?.failure_mode || diseaseSpecificFailure || (
    knownDiseaseAsset
      ? "This signal may collapse if it turns out to be a known in-disease asset rather than a real repurposing opportunity."
      : `This hypothesis weakens sharply if ${input.context.drug_name} cannot shift the disease-relevant biology highlighted in this run.`
  );
  const disconfirmingSignal = critic?.disconfirming_signal || (
    relatedTrial?.phase
      ? `Confidence should drop if ${input.context.drug_name} shows no signal in the currently adjacent ${relatedTrial.phase.toLowerCase()} evidence base or in biomarker-rich disease models.`
      : `Confidence should drop if disease-relevant biomarkers or model readouts fail to move in the expected direction.`
  );
  const criticalTest = critic?.critical_test || (
    asString(hypothesis.testable_prediction) ||
    sentence(`Check whether ${input.context.drug_name} changes biomarkers tied to ${leadPathway} in the subgroup most aligned with the proposed mechanism.`)
  );
  const failureSeverity = critic?.severity ?? (
    input.evidence.breakdown.clinical_evidence <= 5 ? "high" :
    input.evidence.breakdown.clinical_evidence <= 12 ? "medium" :
    "low"
  );
  const failureEvidenceBasis = critic?.evidence_basis ?? (
    supportingPmids.length >= 3 ? "direct" :
    supportingPmids.length >= 1 ? "indirect" :
    "speculative"
  );
  const negativeEvidence = sanitizeReportText(
    Array.from(
      new Set(
        [criticSummary, evidenceConfounders, diseaseSpecificFailure, failureMode, disconfirmingSignal, mainRisk, normalizedEvidence.rationale]
          .flatMap((value) =>
            value
              .split(/(?<=[.!?])\s+/)
              .map((part) => part.trim())
              .filter(Boolean)
          )
      )
    ).join(" ")
  );
  const [adjustedScore, rankingFlags] = computeAdjustedScore(normalizedEvidence, knownDiseaseAsset, negativeEvidence, failureSeverity);
  const diseaseLinkAssessment = assessDiseaseLinkStrength({
    diseaseName: input.diseaseName,
    context: input.context,
    hypothesis,
    pathway: input.pathway,
    literatureMap: input.literatureMap,
    supportingPmids,
    failureEvidenceBasis
  });
  const finalAdjustedScore = Math.max(0, adjustedScore - diseaseLinkAssessment.penalty);
  const finalRankingFlags = Array.from(new Set([...rankingFlags, ...diseaseLinkAssessment.flags]));
  const confidence = deriveConfidence({
    hypothesis,
    adjustedScore: finalAdjustedScore,
    failureSeverity,
    geneticTier: normalizedEvidence.genetic_assessment.tier
  });
  const confidenceDrivers = buildConfidenceDrivers({
    evidence: normalizedEvidence,
    geneticAssessment: normalizedEvidence.genetic_assessment,
    failureSeverity
  });
  const displayName = buildDisplayCandidateName({
    context: input.context,
    hypothesis,
    pathway: input.pathway
  });

  const candidate: ReportTopCandidate = {
    drug_name: input.context.drug_name,
    display_name: displayName,
    molecule_chembl_id: input.context.molecule_chembl_id,
    max_phase: input.context.max_phase,
    is_approved: input.context.is_approved,
    source_type: input.context.source,
    mechanism_hypothesis: compactNarrative(
      asString(hypothesis.mechanism_hypothesis) || buildMechanismHypothesis(input.context, input.diseaseName),
      { maxSentences: 3, maxChars: 480 }
    ),
    current_use: asString(hypothesis.current_use) || currentUse,
    why_candidate: compactNarrative(
      asString(hypothesis.rationale) || buildWhyCandidate(input.context, input.evidence, input.diseaseName),
      { maxSentences: 3, maxChars: 480 }
    ),
    main_risk: compactNarrative(mainRisk, { maxSentences: 2, maxChars: 320 }),
    mechanism_overlap: compactNarrative(
      asString(hypothesis.mechanism_overlap) || `${input.context.mechanism} The most salient pathway context in this run is ${leadPathway}.`,
      { maxSentences: 2, maxChars: 360 }
    ),
    testable_prediction:
      compactNarrative(
        asString(hypothesis.testable_prediction) ||
        sentence(
        `Test whether ${input.context.drug_name} shifts biomarkers tied to ${leadPathway} in ${input.diseaseName} models${relatedTrial?.phase ? ` before leaning on the current ${relatedTrial.phase.toLowerCase()} clinical adjacency` : ""}.`
        ),
        { maxSentences: 3, maxChars: 420 }
      ),
    candidate_role:
      asString(hypothesis.candidate_role) ||
      (input.context.source === "opentargets" ? "target-linked prioritization candidate" : "activity-led prioritization candidate"),
    biomarker_link: asString(hypothesis.biomarker_link) || (input.context.molecule_chembl_id ? `Track target engagement around ${input.context.molecule_chembl_id} linked biology.` : ""),
    subgroup_link: asString(hypothesis.subgroup_link),
    confidence,
    supporting_pmids: supportingPmids,
    total_score: normalizedEvidence.score,
    literature_score: normalizedEvidence.breakdown.literature_support,
    mechanism_score: normalizedEvidence.breakdown.mechanism_overlap,
    clinical_score: normalizedEvidence.breakdown.clinical_evidence,
    safety_score: normalizedEvidence.breakdown.safety_profile,
    genetic_score: normalizedEvidence.breakdown.genetic_support,
    genetic_confidence_tier: normalizedEvidence.genetic_assessment.tier,
    genetic_signal_direction: normalizedEvidence.genetic_assessment.direction,
    genetic_signal_provenance: normalizedEvidence.genetic_assessment.provenance,
    genetic_penalty_reason: normalizedEvidence.genetic_assessment.penalty_reason,
    known_disease_asset: knownDiseaseAsset,
    repurposing_note: compactNarrative(repurposingNote, { maxSentences: 2, maxChars: 220 }),
    negative_evidence: negativeEvidence,
    score_rationale: compactNarrative(
      sanitizeReportText(`${normalizedEvidence.rationale} ${diseaseLinkAssessment.summary}`),
      { maxSentences: 3, maxChars: 480 }
    ),
    evidence_quality_note: buildEvidenceQualityNote(input.evidence.supporting_pmids, input.literatureMap),
    evidence_trace: buildEvidenceTrace(supportingPmids, input.literatureMap),
    adjusted_score: finalAdjustedScore,
    ranking_flags: finalRankingFlags,
    novelty_class: asString(hypothesis.novelty_class) === "novel" ? "novel" : "mainstream",
    novelty_basis: compactNarrative(asString(hypothesis.novelty_basis), { maxSentences: 2, maxChars: 300 }),
    causal_support: compactNarrative(buildCausalSupport(input.context, input.pathway, hypothesis), { maxSentences: 2, maxChars: 300 }),
    false_positive_risk: diseaseSpecificFailure || (
      compactNarrative(
        knownDiseaseAsset
          ? "This may reflect an existing in-disease program rather than a true repurposing opportunity."
          : rankingFlags.includes("weak_clinical_support")
          ? "This may rank well on mechanism, even though disease-specific human evidence is still limited."
            : "The biology may look relevant without being central enough to drive clinical benefit.",
        { maxSentences: 2, maxChars: 320 }
      )
    ),
    discovery_fit: knownDiseaseAsset
      ? "Known in-disease asset"
      : input.context.is_approved
        ? "Repurposing fit"
        : input.context.max_phase >= 1
          ? "Clinical-stage fit"
          : "Early research fit",
    mechanism_cluster: "",
    common_failure_pattern: "",
    failure_mode: compactNarrative(failureMode, { maxSentences: 3, maxChars: 520 }),
    disconfirming_signal: compactNarrative(disconfirmingSignal, { maxSentences: 3, maxChars: 520 }),
    critical_test: compactNarrative(criticalTest, { maxSentences: 3, maxChars: 560 }),
    failure_severity: failureSeverity,
    failure_evidence_basis: failureEvidenceBasis,
    confidence_drivers: confidenceDrivers
  };

  candidate.mechanism_hypothesis = replaceCandidateIdentifiers(candidate.mechanism_hypothesis, candidate);
  candidate.current_use = replaceCandidateIdentifiers(candidate.current_use, candidate);
  candidate.why_candidate = replaceCandidateIdentifiers(candidate.why_candidate, candidate);
  candidate.main_risk = replaceCandidateIdentifiers(candidate.main_risk, candidate);
  candidate.mechanism_overlap = replaceCandidateIdentifiers(candidate.mechanism_overlap, candidate);
  candidate.testable_prediction = replaceCandidateIdentifiers(candidate.testable_prediction, candidate);
  candidate.biomarker_link = replaceCandidateIdentifiers(candidate.biomarker_link, candidate);
  candidate.subgroup_link = replaceCandidateIdentifiers(candidate.subgroup_link, candidate);
  candidate.repurposing_note = replaceCandidateIdentifiers(candidate.repurposing_note, candidate);
  candidate.negative_evidence = replaceCandidateIdentifiers(candidate.negative_evidence, candidate);
  candidate.score_rationale = replaceCandidateIdentifiers(candidate.score_rationale, candidate);
  candidate.evidence_quality_note = replaceCandidateIdentifiers(candidate.evidence_quality_note, candidate);
  candidate.novelty_basis = replaceCandidateIdentifiers(candidate.novelty_basis, candidate);
  candidate.causal_support = replaceCandidateIdentifiers(candidate.causal_support, candidate);
  candidate.false_positive_risk = replaceCandidateIdentifiers(candidate.false_positive_risk, candidate);
  candidate.failure_mode = replaceCandidateIdentifiers(candidate.failure_mode, candidate);
  candidate.disconfirming_signal = replaceCandidateIdentifiers(candidate.disconfirming_signal, candidate);
  candidate.critical_test = replaceCandidateIdentifiers(candidate.critical_test, candidate);
  candidate.confidence_drivers = {
    ...candidate.confidence_drivers,
    summary: replaceCandidateIdentifiers(candidate.confidence_drivers.summary, candidate)
  };
  candidate.mechanism_cluster = inferMechanismCluster(candidate);
  candidate.common_failure_pattern = inferCommonFailurePattern(candidate);
  return candidate;
}

function pickEvidenceSource(candidate: ReportTopCandidate): string {
  const pmid = candidate.supporting_pmids[0];
  return pmid ? `https://pubmed.ncbi.nlm.nih.gov/${pmid}/` : "https://pubmed.ncbi.nlm.nih.gov/";
}

function buildEvidenceTable(candidates: ReportTopCandidate[]): EvidenceRow[] {
  return candidates.map((candidate) => ({
    drug_name: candidate.drug_name,
    display_name: candidate.display_name,
    molecule_chembl_id: candidate.molecule_chembl_id,
    summary: sentence(
      `${candidate.why_candidate} ${candidate.false_positive_risk || candidate.main_risk} ${candidate.evidence_quality_note}`
    ).slice(0, 400),
    source: pickEvidenceSource(candidate),
    score: clamp(candidate.adjusted_score ?? candidate.total_score ?? 0, 0, 100)
  }));
}

function buildDeterministicChecks(input: {
  topCandidates: ReportTopCandidate[];
  evidenceTable: EvidenceRow[];
  evidenceScores: EvidenceScore[];
}): DeterministicChecks {
  const evidenceScoreChecks = input.evidenceScores.map((entry) => {
    const breakdownSum =
      entry.breakdown.literature_support +
      entry.breakdown.mechanism_overlap +
      entry.breakdown.clinical_evidence +
      entry.breakdown.safety_profile +
      entry.breakdown.genetic_support;

    return {
      drug_name: entry.drug_name,
      display_name:
        input.topCandidates.find((candidate) => candidate.drug_name.toLowerCase() === entry.drug_name.toLowerCase())?.display_name ||
        entry.drug_name,
      molecule_chembl_id:
        input.topCandidates.find((candidate) => candidate.drug_name.toLowerCase() === entry.drug_name.toLowerCase())?.molecule_chembl_id ||
        entry.molecule_chembl_id,
      reported_score: entry.score,
      breakdown_sum: breakdownSum,
      sum_matches_score: breakdownSum === entry.score,
      breakdown: entry.breakdown
    };
  });

  const evidenceTableNames = new Set(input.evidenceTable.map((row) => row.drug_name.toLowerCase()));
  const evidenceScoreNames = new Set(input.evidenceScores.map((row) => row.drug_name.toLowerCase()));
  const drugCoverageChecks = input.topCandidates.map((candidate) => {
    const drugName = candidate.drug_name.toLowerCase();
    return {
      drug_name: candidate.drug_name,
      in_evidence_table: evidenceTableNames.has(drugName),
      in_evidence_scores: evidenceScoreNames.has(drugName)
    };
  });

  return {
    note:
      "Deterministic consistency checks were computed by the orchestration layer before evaluator review so score arithmetic and drug coverage do not rely on model judgment.",
    evidence_score_checks: evidenceScoreChecks,
    drug_coverage_checks: drugCoverageChecks,
    all_scores_valid: evidenceScoreChecks.every((item) => item.sum_matches_score),
    all_drugs_covered: drugCoverageChecks.every(
      (item) => item.in_evidence_table && item.in_evidence_scores
    )
  };
}

function buildRedTeamMap(redTeam: JsonRecord | undefined): Map<string, RedTeamCritique> {
  return new Map(
    asArray<JsonRecord>(redTeam?.critiques).map((critique) => {
      const normalized = {
        drug_name: asString(critique.drug_name),
        translation_risk: asString(critique.translation_risk),
        evidence_confounders: asString(critique.evidence_confounders),
        disease_specific_failure: asString(critique.disease_specific_failure),
        failure_mode: asString(critique.failure_mode) || asString(critique.disease_specific_failure),
        disconfirming_signal: asString(critique.disconfirming_signal),
        critical_test: asString(critique.critical_test),
        severity:
          asString(critique.severity) === "high" || asString(critique.severity) === "medium" || asString(critique.severity) === "low"
            ? (asString(critique.severity) as "low" | "medium" | "high")
            : "medium",
        evidence_basis:
          asString(critique.evidence_basis) === "direct" || asString(critique.evidence_basis) === "indirect" || asString(critique.evidence_basis) === "speculative"
            ? (asString(critique.evidence_basis) as "direct" | "indirect" | "speculative")
            : "indirect",
        summary: asString(critique.summary)
      } satisfies RedTeamCritique;
      return [normalized.drug_name.toUpperCase(), normalized];
    })
  );
}

function buildSuppressedCandidateNote(candidates: ReportTopCandidate[]): string {
  if (candidates.length === 0) return "";
  const opaqueCount = candidates.filter(
    (candidate) =>
      isOpaqueCandidateId(candidate.drug_name) ||
      isOpaqueCandidateId(candidate.display_name) ||
      candidate.display_name.trim().toLowerCase() === "investigational candidate"
  ).length;
  const weakClinicalCount = candidates.filter((candidate) => candidate.ranking_flags.includes("weak_clinical_support")).length;
  const highFailureCount = candidates.filter((candidate) => candidate.ranking_flags.includes("high_failure_risk")).length;

  if (opaqueCount === candidates.length) {
    return `The drug hits did not resolve into reportable candidates.`;
  }
  if (weakClinicalCount === candidates.length || highFailureCount === candidates.length) {
    return `The candidates remained mechanism-led, with limited clinical support and higher failure risk.`;
  }
  return `The available candidates did not meet the current reportability threshold for identity quality, clinical support, and failure risk.`;
}

function buildSummary(
  query: string,
  candidates: ReportTopCandidate[],
  suppressedCandidateNote = "",
  earlyStageHypotheses: ReportTopCandidate[] = [],
  reviewedSignalCandidates: ReportTopCandidate[] = []
): string {
  if (candidates.length === 0) {
    if (earlyStageHypotheses.length > 0) {
      const lead = earlyStageHypotheses[0];
      return compactNarrative(
        `The workflow completed for ${query}, but this run did not produce a reportable candidate shortlist. ` +
          `${lead.display_name} remained as an early-stage hypothesis with indirect support, so it was kept for follow-up review rather than presented as a prioritized candidate. ` +
          `${suppressedCandidateNote}`,
        { maxSentences: 4, maxChars: 520 }
      );
    }
    if (reviewedSignalCandidates.length > 0) {
      return compactNarrative(
        `The workflow completed for ${query}, but this run did not produce a reportable candidate shortlist. ` +
          `${reviewedSignalCandidates.length} weak mechanism-linked signal${reviewedSignalCandidates.length === 1 ? " was" : "s were"} retained for follow-up review, but none cleared the bar for a prioritized candidate or formal early-stage hypothesis. ` +
          `${suppressedCandidateNote}`,
        { maxSentences: 4, maxChars: 560 }
      );
    }
    return compactNarrative(
      `The workflow completed for ${query}, but this run did not produce a final candidate shortlist. ` +
        `${suppressedCandidateNote}`,
      { maxSentences: 3, maxChars: 420 }
    );
  }
  const lead = candidates[0];
  const novelCount = candidates.filter((candidate) => candidate.novelty_class === "novel").length;
  const mainCaveat =
    lead.false_positive_risk ||
    lead.negative_evidence ||
    lead.main_risk ||
    "The output remains a research prioritization artifact rather than a treatment recommendation.";
  return compactNarrative(
    `This workflow identified ${candidates.length} candidate signals for ${query}. ` +
      `${lead.display_name} ranked highest after literature, mechanism, clinical, safety, and genetic weighting, with an adjusted score of ${lead.adjusted_score ?? lead.total_score ?? 0}. ` +
      `${novelCount} candidate${novelCount === 1 ? "" : "s"} met the current novelty gate in this pass. ` +
      `Lead caveat: ${mainCaveat}`
  , { maxSentences: 5, maxChars: 700 });
}

function buildCommonFailurePatternSummary(candidates: ReportTopCandidate[]): string {
  const discoveryCandidates = candidates.filter((candidate) => candidate.known_disease_asset !== true);
  if (discoveryCandidates.length < 2) return "";

  const patternCounts = new Map<string, number>();
  for (const candidate of discoveryCandidates) {
    const pattern = sentence(candidate.common_failure_pattern || "");
    if (!pattern) continue;
    patternCounts.set(pattern, (patternCounts.get(pattern) ?? 0) + 1);
  }

  const dominantPattern = [...patternCounts.entries()].sort((a, b) => b[1] - a[1])[0];
  if (!dominantPattern || dominantPattern[1] < 2) return "";

  const topClusters = [...new Set(discoveryCandidates.map((candidate) => candidate.mechanism_cluster).filter(Boolean))].slice(0, 3);
  const clusterText = topClusters.length > 0 ? ` This affects multiple mechanism families in the current shortlist (${topClusters.join(", ")}).` : "";

  return sentence(
    `Several shortlisted candidates may fail for the same reason: ${dominantPattern[0]}. ` +
    `If that assumption breaks, multiple candidates in this report could weaken together rather than independently.${clusterText}`
  );
}

function buildNovelSearchNarrative(input: {
  reportableCandidates: ReportTopCandidate[];
  earlyStageHypotheses: ReportTopCandidate[];
  rawNovelSearchNote: string;
}): string {
  const raw = sanitizeReportText(input.rawNovelSearchNote);
  if (input.reportableCandidates.length === 0 && input.earlyStageHypotheses.length > 0) {
    const lead = input.earlyStageHypotheses[0];
    return sentence(
      raw
        ? `${raw} In this run, however, ${lead.display_name} remained an early-stage hypothesis with indirect support rather than a reportable candidate.`
        : `${lead.display_name} remained an early-stage cross-indication hypothesis in this run. The mechanism fit was indirect, so the output was kept for follow-up review rather than presented as a reportable candidate.`
    );
  }
  return raw;
}

function buildMethodologyText(input: {
  diseaseName: string;
  literatureCount: number;
  literatureReviewedCount: number;
  fullTextCount: number;
  candidateCount: number;
  candidateReviewedCount: number;
  hypothesisCount: number;
  novelCount: number;
  scoredCount: number;
  pathwayCount: number;
  trialCount: number;
  geneticCount: number;
  paymentProofCount: number;
  pathwayAnchors: string[];
  novelSearchNote: string;
  hasReportableCandidates: boolean;
  hasEarlyStageHypotheses: boolean;
  reviewedSignalCount: number;
  userType: "pharma" | "researcher" | "doctor";
}): string {
  const audienceNote: Record<"pharma" | "researcher" | "doctor", string> = {
    pharma: "The writeup emphasizes triage, translational risk, and next-step prioritization for portfolio review.",
    researcher: "The writeup emphasizes assumptions, evidence gaps, and why the current ranking should be treated as a research prioritization layer rather than a conclusion.",
    doctor: "The writeup emphasizes concise interpretation and explicitly avoids treatment guidance or dosing advice."
  };
  const pathwayNote =
    input.pathwayAnchors.length > 0
      ? `The clearest biology signals in this run were ${input.pathwayAnchors.slice(0, 3).join(", ")}. `
      : "";
  const noveltyNote = input.novelSearchNote
    ? `${sanitizeReportText(input.novelSearchNote)} `
    : input.novelCount > 0
      ? `${input.novelCount} candidate${input.novelCount === 1 ? "" : "s"} stood out as a plausible cross-indication opportunity in this pass. `
      : "No candidate stood out strongly enough in this pass to be presented as a clear discovery lead. ";
  const paymentNote =
    input.paymentProofCount > 0
      ? `The report provenance also records ${input.paymentProofCount} workflow transaction${input.paymentProofCount === 1 ? "" : "s"} so the research trail remains traceable. `
      : "";
  const sourceReviewNote =
    input.fullTextCount > 0
      ? `The literature layer used prioritized literature screening, with targeted source verification on ${input.fullTextCount} shortlisted paper${input.fullTextCount === 1 ? "" : "s"}, before downstream scoring and report assembly. `
      : `The literature layer used prioritized literature screening before downstream scoring and report assembly. `;
  const downstreamNote =
    input.hypothesisCount === 0
      ? input.reviewedSignalCount > 0
        ? `Repurposing did not produce a shortlist, so formal scoring did not continue; however, ${input.reviewedSignalCount} weak mechanism-linked signal${input.reviewedSignalCount === 1 ? " was" : "s were"} retained for follow-up review. `
        : `Repurposing did not produce a shortlist, so scoring and red-team review did not continue in this run. `
      : input.scoredCount === 0
        ? `A shortlist was formed, but no candidate progressed into the final scoring layer in this run. `
        : "";
  const candidateOutcomeNote =
    !input.hasReportableCandidates && input.hasEarlyStageHypotheses
      ? "This run produced an early-stage hypothesis rather than a reportable candidate shortlist. "
      : !input.hasReportableCandidates && input.reviewedSignalCount > 0
        ? `This run retained ${input.reviewedSignalCount} reviewed weak signal${input.reviewedSignalCount === 1 ? "" : "s"} for follow-up, but none cleared the stronger threshold for a reportable candidate or formal early-stage hypothesis. `
      : !input.hasReportableCandidates
        ? "This run did not produce a reportable candidate shortlist. "
        : "";
  return sentence(
    `This report was assembled through the current research workflow for ${input.diseaseName}. ` +
      `The literature agent retrieved ${input.literatureReviewedCount} papers and carried ${input.literatureCount} into the final report set, while the drug database stage reviewed ${input.candidateReviewedCount} candidate records and surfaced ${input.candidateCount} normalized candidate contexts for downstream triage. ` +
      `The pathway stage contributed ${input.pathwayCount} pathway records and ${input.trialCount} active clinical trial links. ` +
      `The repurposing, evidence, and red-team stages then turned those signals into ${input.hypothesisCount} candidate hypotheses, a shortlist, a structured scoring layer, and candidate-specific challenge notes before final report assembly and safety validation. ` +
      `The ranking uses a fixed 100-point rubric with literature support (0-30), mechanism overlap (0-30), clinical evidence (0-20), safety profile (0-10), and genetic support (-10 to +10) across ${input.scoredCount} scored candidates. ` +
      `${candidateOutcomeNote}${pathwayNote}${noveltyNote}${sourceReviewNote}${downstreamNote}${paymentNote}` +
      `Key limitations: genetic support ${input.geneticCount > 0 ? "was included as supportive disease-biology context" : "was not available in this run"}, these outputs are still prioritization-grade rather than causal proof, and the report layer does not claim target validation or treatment efficacy. ` +
      `${audienceNote[input.userType]}`
  );
}

export function runReportSafetyChecks(payload: Pick<ReportPayload, "disclaimer" | "provenance" | "report">): string[] {
  const errors: string[] = [];
  const disclaimer = payload.disclaimer.toLowerCase();
  const allowsNoHit =
    payload.report.no_hit === true ||
    payload.report.summary.toLowerCase().includes("did not produce a reportable repurposing candidate");
  const hasTopCandidates = Array.isArray(payload.report.top_candidates) && payload.report.top_candidates.length > 0;
  const hasEarlyStageHypotheses =
    Array.isArray(payload.report.early_stage_hypotheses) && payload.report.early_stage_hypotheses.length > 0;
  const hasReviewedSignals =
    Array.isArray(payload.report.reviewed_signal_candidates) && payload.report.reviewed_signal_candidates.length > 0;
  const hasDeliverableSignal = hasTopCandidates || hasEarlyStageHypotheses || hasReviewedSignals;

  if (
    payload.report.no_hit === true &&
    !hasEarlyStageHypotheses &&
    !hasReviewedSignals
  ) {
    errors.push("no_reportable_signal");
  }
  for (const phrase of REQUIRED_DISCLAIMER_PHRASES) {
    if (!disclaimer.includes(phrase.toLowerCase())) {
      errors.push(`disclaimer_missing_phrase: ${phrase}`);
    }
  }

  if (!payload.provenance.pmids_used.length && !allowsNoHit) errors.push("provenance_missing: pmids_used empty");
  if (!Object.keys(payload.provenance.models_used).length) errors.push("provenance_missing: models_used empty");
  if (!payload.provenance.timestamp) errors.push("provenance_missing: timestamp empty");

  if (!hasDeliverableSignal && !allowsNoHit) errors.push("report_missing: deliverable_signal empty");
  if (!hasTopCandidates && !hasEarlyStageHypotheses && !hasReviewedSignals && !allowsNoHit) {
    errors.push("report_missing: top_candidates empty");
  }
  if (!payload.report.evidence_table.length && !hasEarlyStageHypotheses && !hasReviewedSignals && !allowsNoHit) {
    errors.push("report_missing: evidence_table empty");
  }
  if (!payload.report.methodology.trim()) errors.push("report_missing: methodology empty");

  for (const candidate of payload.report.top_candidates) {
    if (!candidate.mechanism_overlap.trim()) {
      errors.push(`top_candidate_missing_mechanism: ${candidate.drug_name}`);
    }
    if (!candidate.supporting_pmids.length) {
      errors.push(`top_candidate_missing_pmids: ${candidate.drug_name}`);
    }
  }

  for (const row of payload.report.evidence_table) {
    if (row.score < 0 || row.score > 100) {
      errors.push(`evidence_row_score_out_of_range: ${row.drug_name}`);
    }
    if (row.summary.trim().length < 30) {
      errors.push(`evidence_row_summary_short: ${row.drug_name}`);
    }
    if (!row.source) {
      errors.push(`evidence_row_missing_source: ${row.drug_name}`);
    }
  }

  return errors;
}

export function buildReportPayload(input: {
  jobId: string;
  query: string;
  literature: JsonRecord;
  drugdb: JsonRecord;
  pathway?: JsonRecord;
  repurposing?: JsonRecord;
  evidence?: JsonRecord;
  redTeam?: JsonRecord;
  evaluator: JsonRecord;
  paymentProofs?: Array<{
    agent: string;
    endpoint?: string;
    seller?: string;
    payer?: string;
    network?: string;
    transaction?: string;
    settled?: boolean;
  }>;
  userType?: "pharma" | "researcher" | "doctor";
}): ReportPayload {
  const userType = input.userType ?? "researcher";
  const pathway = input.pathway ?? {};
  const repurposing = input.repurposing ?? {};
  const evidence = input.evidence ?? {};
  const literaturePapers = buildLiteraturePaperCards(input.literature);
  const literatureMap = buildLiteratureMap(literaturePapers);
  const drugContexts = buildDrugContexts(input.drugdb, input.query);
  const fallbackEvidenceScores = drugContexts
    .map((context) => buildEvidenceScore(context, literaturePapers))
    .sort((left, right) => right.score - left.score)
    .slice(0, 10);
  const hypothesisMap = buildHypothesisMap(repurposing);
  const evidenceMap = buildEvidenceMap(evidence);
  const redTeamMap = buildRedTeamMap(input.redTeam);
  const contextByDrugName = new Map(drugContexts.map((context) => [context.drug_name.toUpperCase(), context]));
  const shouldSuppressFallbackCandidates =
    hypothesisMap.size === 0 &&
    evidenceMap.size === 0;
  const rawEvidenceScores =
    evidenceMap.size > 0
      ? [...evidenceMap.values()]
      : shouldSuppressFallbackCandidates
        ? []
        : fallbackEvidenceScores;
  const normalizedEvidenceScores = rawEvidenceScores.map((entry) => {
    const context = contextByDrugName.get(entry.drug_name.toUpperCase()) ?? {
      drug_name: entry.drug_name,
      molecule_chembl_id: entry.molecule_chembl_id,
      current_indications: [],
      mechanism: `Derived from the available drug evidence collected for ${input.query}.`,
      max_phase: 0,
      is_approved: false,
      source: "chembl_activity" as const
    };
    return normalizeEvidenceScore({
      evidence: entry,
      context,
      pathway,
      hypothesis: hypothesisMap.get(entry.drug_name.toUpperCase()) ?? {},
      critic: redTeamMap.get(entry.drug_name.toUpperCase())
    });
  });
  const reviewedSignalCandidates = applyMechanismDiversity(
    fallbackEvidenceScores
      .map((evidence) =>
        buildCandidatePayload({
          diseaseName: input.query,
          context: contextByDrugName.get(evidence.drug_name.toUpperCase()) ?? {
            drug_name: evidence.drug_name,
            molecule_chembl_id: evidence.molecule_chembl_id,
            current_indications: [],
            mechanism: `Derived from the available drug evidence collected for ${input.query}.`,
            max_phase: 0,
            is_approved: false,
            source: "chembl_activity"
          },
          evidence,
          literatureMap,
          pathway,
          hypothesis: hypothesisMap.get(evidence.drug_name.toUpperCase()),
          critic: redTeamMap.get(evidence.drug_name.toUpperCase())
        })
      )
      .sort(
        (left, right) =>
          (right.adjusted_score ?? right.total_score ?? 0) - (left.adjusted_score ?? left.total_score ?? 0) ||
          left.display_name.localeCompare(right.display_name)
      )
  ).slice(0, 6);
  const candidatePool = applyMechanismDiversity(
    rawEvidenceScores
    .map((evidence) =>
      buildCandidatePayload({
        diseaseName: input.query,
        context: contextByDrugName.get(evidence.drug_name.toUpperCase()) ?? {
          drug_name: evidence.drug_name,
          molecule_chembl_id: evidence.molecule_chembl_id,
          current_indications: [],
          mechanism: `Derived from the available drug evidence collected for ${input.query}.`,
          max_phase: 0,
          is_approved: false,
          source: "chembl_activity"
        },
        evidence,
        literatureMap,
        pathway,
        hypothesis: hypothesisMap.get(evidence.drug_name.toUpperCase()),
        critic: redTeamMap.get(evidence.drug_name.toUpperCase())
      })
    )
    .sort(
      (left, right) =>
        (right.adjusted_score ?? right.total_score ?? 0) - (left.adjusted_score ?? left.total_score ?? 0) ||
        left.display_name.localeCompare(right.display_name)
    )
  );
  const topCandidates = filterReportableCandidates(candidatePool, input.query);
  const earlyStageHypotheses = filterEarlyStageHypotheses(
    candidatePool.filter(
      (candidate) => !topCandidates.some((selected) => selected.drug_name.toUpperCase() === candidate.drug_name.toUpperCase())
    )
  );
  const suppressedCandidates = candidatePool.filter(
    (candidate) =>
      !topCandidates.some((selected) => selected.drug_name.toUpperCase() === candidate.drug_name.toUpperCase()) &&
      !earlyStageHypotheses.some((selected) => selected.drug_name.toUpperCase() === candidate.drug_name.toUpperCase())
  );
  const suppressedCandidateNote = buildSuppressedCandidateNote(suppressedCandidates);
  const evidenceTable = buildEvidenceTable(topCandidates);
  const noHit = topCandidates.length === 0;
  const shortlistGenerated = asArray<JsonRecord>(repurposing.hypotheses).length > 0;
  const pipelineStoppedBeforeShortlist = !shortlistGenerated && normalizedEvidenceScores.length === 0;
  const literatureDiagnostics = buildLiteratureDiagnostics(input.literature);
  const deterministicChecks = buildDeterministicChecks({
    topCandidates,
    evidenceTable,
    evidenceScores: normalizedEvidenceScores
  });
  const literatureStats = asRecord(input.literature.retrieval_stats);
  const drugdbStats = asRecord(input.drugdb.retrieval_stats);

  const pathwayRows = asArray<JsonRecord>(pathway.pathways);
  const clinicalTrials = asArray<JsonRecord>(pathway.clinical_trials);
  const trialContexts = buildTrialContexts(pathway);
  const geneticEvidence = asArray<JsonRecord>(pathway.genetic_evidence);
  const pathwayAnchors = buildPathwayAnchors(pathway);
  const paymentProofs = asArray<JsonRecord>(input.paymentProofs)
    .map((proof) => ({
      agent: asString(proof.agent),
      endpoint: asString(proof.endpoint),
      mode: asString(proof.mode),
      seller: asString(proof.seller),
      payer: asString(proof.payer),
      network: asString(proof.network),
      transaction: asString(proof.transaction),
      settled: proof.settled === false ? false : true
    }))
    .filter((proof) => proof.agent && proof.transaction);
  const provenance = {
    pmids_used: literaturePapers.map((paper) => paper.pmid).filter(Boolean).slice(0, 10),
    chembl_ids_used: topCandidates.map((context) => context.molecule_chembl_id).filter(Boolean).slice(0, 10),
    nct_ids_used: clinicalTrials.map((trial) => asString(trial.nct_id)).filter(Boolean).slice(0, 10),
    models_used: {
      literature: "paid-gateway-literature",
      drugdb: "paid-gateway-drugdb",
      pathway: modelLabel(input.pathway, "internal-opentargets-pathway"),
      repurposing: modelLabel(input.repurposing, "internal-repurposing"),
      evidence: modelLabel(input.evidence, "internal-evidence"),
      red_team: modelLabel(input.redTeam, "internal-red-team"),
      evaluator: "paid-gateway-evaluator",
      report: "deterministic-report-builder"
    },
    timestamp: new Date().toISOString(),
    payments: paymentProofs
  };

  const report: ReportContent = {
    disclaimer: DISCLAIMER,
    summary: buildSummary(input.query, topCandidates, suppressedCandidateNote, earlyStageHypotheses, pipelineStoppedBeforeShortlist ? reviewedSignalCandidates : []),
    retrieval_note: buildLiteratureRetrievalNote(input.literature),
    literature_diagnostics: literatureDiagnostics,
    drugdb_note: buildDrugdbRetrievalNote(asRecord(input.drugdb)),
    repurposing_note: buildRepurposingNote(asRecord(input.repurposing), asRecord(input.drugdb)),
    evidence_note: buildEvidenceNote(asRecord(input.evidence), asRecord(input.repurposing)),
    red_team_note: buildRedTeamNote(asRecord(input.redTeam), asRecord(input.evidence)),
    no_hit: noHit,
    shortlist_generated: shortlistGenerated,
    pipeline_stopped_before_shortlist: pipelineStoppedBeforeShortlist,
    suppressed_candidate_count: suppressedCandidates.length,
    suppressed_candidate_note: suppressedCandidateNote,
    user_type: userType,
    top_candidates: topCandidates,
    early_stage_hypotheses: earlyStageHypotheses,
    novel_candidates: topCandidates.filter((candidate) => candidate.novelty_class === "novel"),
    reviewed_signal_candidates: pipelineStoppedBeforeShortlist ? reviewedSignalCandidates : [],
    evidence_table: evidenceTable,
    literature_papers: literaturePapers,
    active_trials: trialContexts,
    genetic_evidence_summary: buildGeneticEvidenceSummary(pathway, userType),
    novel_search_note: replaceOpaqueIdsInReportText(
      buildNovelSearchNarrative({
        reportableCandidates: topCandidates,
        earlyStageHypotheses,
        rawNovelSearchNote: asString(repurposing.novel_search_note)
      }),
      [...topCandidates, ...earlyStageHypotheses]
    ),
    common_failure_pattern_summary: buildCommonFailurePatternSummary(topCandidates),
    methodology: buildMethodologyText({
      diseaseName: input.query,
      literatureCount: literaturePapers.length,
      literatureReviewedCount: asNumber(literatureStats.retrieved_count) || literaturePapers.length,
      fullTextCount: literaturePapers.filter((paper) => paper.content_level === "full_text").length,
      candidateCount: drugContexts.length,
      candidateReviewedCount: asNumber(drugdbStats.expanded_candidate_count) || drugContexts.length,
      hypothesisCount: asArray<JsonRecord>(repurposing.hypotheses).length,
      novelCount: topCandidates.filter((candidate) => candidate.novelty_class === "novel").length,
      scoredCount: normalizedEvidenceScores.length,
      pathwayCount: pathwayRows.length,
      trialCount: clinicalTrials.length,
      geneticCount: geneticEvidence.length,
      paymentProofCount: paymentProofs.length,
      pathwayAnchors,
      novelSearchNote: asString(repurposing.novel_search_note),
      hasReportableCandidates: topCandidates.length > 0,
      hasEarlyStageHypotheses: earlyStageHypotheses.length > 0,
      reviewedSignalCount: pipelineStoppedBeforeShortlist ? reviewedSignalCandidates.length : 0,
      userType
    }),
    deterministic_checks: deterministicChecks,
    provenance,
    evaluator_summary: {
      decision: asString(input.evaluator.decision) || "unknown",
      reason: asString(input.evaluator.reason)
    }
  };

  return {
    agent: "report",
    status: "success",
    report,
    disclaimer: DISCLAIMER,
    provenance,
    ipfs_hash: `0x${createHash("sha256").update(JSON.stringify(report)).digest("hex")}`,
    error: null,
    evidence_scores: normalizedEvidenceScores
  };
}
import { createHash } from "node:crypto";
